  `retro` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci,
  PRIMARY KEY (`id`),
  KEY `saved_report_id` (`saved_report_id`),
  CONSTRAINT `saved_reports_options_ibfk_1` FOREIGN KEY (`saved_report_id`) REFERENCES `saved_reports` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


DROP TABLE IF EXISTS `segment_contents`;
CREATE TABLE `segment_contents` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `usecase_segment_id` int unsigned NOT NULL,
  `segment_num` tinyint unsigned NOT NULL,
  `min_score` tinyint NOT NULL,
  `file` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `content` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci,
  `content_from` tinyint(1) NOT NULL COMMENT '1 = from file, 2 = from text',
  `instruction_prompt` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci,
  `evaluation_prompt` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci,
  `date_created` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `template` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci,
  `questions` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci,
  PRIMARY KEY (`id`),
  KEY `usecase_segment_id` (`usecase_segment_id`),
  CONSTRAINT `segment_contents_ibfk_1` FOREIGN KEY (`usecase_segment_id`) REFERENCES `usecase_segment` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


DROP TABLE IF EXISTS `site_users`;
CREATE TABLE `site_users` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `customer_id` int unsigned NOT NULL,
  `uname` varchar(190) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `email` varchar(190) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `pwd` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `date_added` datetime NOT NULL,
  PRIMARY KEY (`id`),
  KEY `customer_id` (`customer_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


DROP TABLE IF EXISTS `ugroups`;
CREATE TABLE `ugroups` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `customer_id` int unsigned NOT NULL DEFAULT '1',
  `group_name` varchar(190) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `logo` varchar(190) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `date_created` datetime NOT NULL,
  PRIMARY KEY (`id`),
  KEY `customer_id` (`customer_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


DROP TABLE IF EXISTS `usecase_accents`;
CREATE TABLE `usecase_accents` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `usecase_id` int unsigned NOT NULL,
  `language_code` varchar(190) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `accent_code` varchar(190) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `accent_text` varchar(190) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `class_name` varchar(190) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  PRIMARY KEY (`id`),
  KEY `usecase_id` (`usecase_id`),
  CONSTRAINT `usecase_accents_ibfk_1` FOREIGN KEY (`usecase_id`) REFERENCES `usecases` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


DROP TABLE IF EXISTS `usecase_ai_models`;
CREATE TABLE `usecase_ai_models` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `usecase_id` int unsigned NOT NULL,
  `ai_model_id` int unsigned DEFAULT NULL,
  `display_order` tinyint unsigned NOT NULL DEFAULT '1',
  PRIMARY KEY (`id`),
  KEY `usecase_id` (`usecase_id`),
  KEY `ai_model_id` (`ai_model_id`),
  CONSTRAINT `usecase_ai_models_ibfk_1` FOREIGN KEY (`usecase_id`) REFERENCES `usecases` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `usecase_ai_models_ibfk_2` FOREIGN KEY (`ai_model_id`) REFERENCES `ai_models` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


DROP TABLE IF EXISTS `usecase_avatars`;
CREATE TABLE `usecase_avatars` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `usecase_id` int unsigned NOT NULL,
  `avatar_id` int unsigned NOT NULL,
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '1=true, 0=false',
  PRIMARY KEY (`id`),
  KEY `usecase_id` (`usecase_id`),
  KEY `avatar_id` (`avatar_id`),
  CONSTRAINT `usecase_avatars_ibfk_1` FOREIGN KEY (`usecase_id`) REFERENCES `usecases` (`id`) ON DELETE CASCADE,
  CONSTRAINT `usecase_avatars_ibfk_2` FOREIGN KEY (`avatar_id`) REFERENCES `avatars` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


DROP TABLE IF EXISTS `usecase_customers`;
CREATE TABLE `usecase_customers` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `usecase_id` int unsigned NOT NULL COMMENT 'base use case',
  `customer_id` int unsigned NOT NULL COMMENT 'admin user',
  PRIMARY KEY (`id`),
  KEY `usecase_id` (`usecase_id`),
  CONSTRAINT `usecase_customers_ibfk_3` FOREIGN KEY (`usecase_id`) REFERENCES `usecases` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


DROP TABLE IF EXISTS `usecase_group`;
CREATE TABLE `usecase_group` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `usecase_id` int unsigned NOT NULL,
  `group_id` int unsigned NOT NULL,
  PRIMARY KEY (`id`),
  KEY `usecase_id` (`usecase_id`),
  KEY `group_id` (`group_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


DROP TABLE IF EXISTS `usecase_help_text`;
CREATE TABLE `usecase_help_text` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `usecase_id` int unsigned NOT NULL,
  `name_and_template` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `content` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `sys_instruction` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `avatar_config` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `intro_info` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `pronun_help` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `usecase_id` (`usecase_id`),
  CONSTRAINT `usecase_help_text_ibfk_1` FOREIGN KEY (`usecase_id`) REFERENCES `usecases` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


DROP TABLE IF EXISTS `usecase_instructions`;
CREATE TABLE `usecase_instructions` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `usecase_id` int unsigned NOT NULL,
  `itreaction_no` tinyint unsigned NOT NULL,
  `lang` varchar(40) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `instruction` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  PRIMARY KEY (`id`),
  KEY `usecase_id` (`usecase_id`),
  KEY `lang` (`lang`),
  CONSTRAINT `usecase_instructions_ibfk_1` FOREIGN KEY (`usecase_id`) REFERENCES `usecases` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


DROP TABLE IF EXISTS `usecase_segment`;
CREATE TABLE `usecase_segment` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `usecase_id` int unsigned NOT NULL,
  `title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `usecase_id` (`usecase_id`),
  CONSTRAINT `usecase_segment_ibfk_1` FOREIGN KEY (`usecase_id`) REFERENCES `usecases` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


DROP TABLE IF EXISTS `usecase_stages`;
CREATE TABLE `usecase_stages` (
  `ID` int unsigned NOT NULL AUTO_INCREMENT,
  `coach_usecase_id` int unsigned NOT NULL,
  `sequence` smallint DEFAULT '1',
  `name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `one_liner` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci,
  `instructions` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci,
  PRIMARY KEY (`ID`),
  KEY `coach_usecase_id_sequence` (`coach_usecase_id`,`sequence`),
  CONSTRAINT `usecase_stages_ibfk_1` FOREIGN KEY (`coach_usecase_id`) REFERENCES `coach_usecases` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


DROP TABLE IF EXISTS `usecase_termins`;
CREATE TABLE `usecase_termins` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `usecase_id` int unsigned NOT NULL,
  `language_code` varchar(190) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `phrases` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  PRIMARY KEY (`id`),
  KEY `usecase_id` (`usecase_id`),
  CONSTRAINT `usecase_termins_ibfk_1` FOREIGN KEY (`usecase_id`) REFERENCES `usecases` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


DROP TABLE IF EXISTS `usecases`;
CREATE TABLE `usecases` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `customer_id` int unsigned NOT NULL DEFAULT '1',
  `usecase_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `iteration` tinyint NOT NULL,
  `ai_model_id` int unsigned DEFAULT NULL,
  `lang` varchar(190) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `tool_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '0=none,1=retrieval,2=Code interpreter,3=Functions',
  `logo` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `file_name` varchar(190) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `video_url` varchar(190) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `interaction_type` tinyint unsigned NOT NULL DEFAULT '1' COMMENT '1=Realtime|Video, 2=Realtime, 3=Video, 4=Audio, 5=Realtime|Audio, 6=Audio|Video, 7=All three',
  `realtime_label` varchar(190) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `video_label` varchar(190) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `audio_label` varchar(190) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `instructions` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci,
  `enable_correction_prompt` tinyint(1) NOT NULL DEFAULT '0',
  `correction_prompt` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci,
  `passcode` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `live_retro` tinyint(1) NOT NULL DEFAULT '0',
  `direct_access` tinyint unsigned NOT NULL DEFAULT '0',
  `direct_avatar` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `direct_avatar_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `direct_avatar_accent` varchar(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `direct_interaction_type` tinyint unsigned NOT NULL DEFAULT '1' COMMENT '1=Realtime, 2=Video, 3=Audio',
  `direct_user_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `segmented_content` tinyint(1) NOT NULL DEFAULT '0',
  `date_created` datetime NOT NULL,
  PRIMARY KEY (`id`),
  KEY `usecase_name` (`usecase_name`),
  KEY `customer_id` (`customer_id`),
  KEY `ai_model_id` (`ai_model_id`),
  CONSTRAINT `usecases_ibfk_1` FOREIGN KEY (`ai_model_id`) REFERENCES `ai_models` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


DROP TABLE IF EXISTS `wa_takeda`;
CREATE TABLE `wa_takeda` (
  `ID` int NOT NULL AUTO_INCREMENT,
  `role` varchar(10) NOT NULL,
  `name` varchar(100) NOT NULL,
  `email` varchar(100) NOT NULL,
  `phone` varchar(20) NOT NULL,
  PRIMARY KEY (`ID`),
  KEY `phone` (`phone`),
  KEY `email` (`email`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;


