:900;\r\n    opacity:0.95;\r\n  }\r\n\r\n  .score-right p{\r\n    margin:0;\r\n    font-size:14px;\r\n    line-height:1.35;\r\n    white-space:pre-wrap;\r\n    opacity:0.95;\r\n  }\r\n\r\n  /* Barra decorativa (no requiere % real) */\r\n  .sparkbar{\r\n    margin-top:12px;\r\n    height:10px;\r\n    border-radius:999px;\r\n    overflow:hidden;\r\n    background: rgba(255,255,255,0.20);\r\n  }\r\n.sparkbar span{\r\n  display:block;\r\n  height:100%;\r\n  width:[global_score]%;\r\n  background: rgba(255,255,255,0.85);\r\n}\r\n\r\n  /* ====== CARDS GRID ====== */\r\n  .grid{\r\n    display:grid;\r\n    grid-template-columns: 1fr 1fr;\r\n    gap:14px;\r\n    margin-top:14px;\r\n  }\r\n\r\n  .card{\r\n    border:1px solid #d9dee8;\r\n    border-radius:12px;\r\n    padding:14px;\r\n    background:#f8f9fc;\r\n  }\r\n\r\n  .card h3{\r\n    margin:0 0 8px 0;\r\n    font-size:15px;\r\n    color:#1b2a49;\r\n    font-weight:900;\r\n  }\r\n\r\n  .card p{\r\n    margin:0;\r\n    font-size:15px;\r\n    line-height:1.35;\r\n    white-space:pre-wrap;\r\n  }\r\n\r\n  .full{\r\n    grid-column: 1 / -1;\r\n  }\r\n\r\n  .footer-note{\r\n    margin-top:14px;\r\n    font-size:13px;\r\n    color:#555;\r\n  }\r\n\r\n  @media (max-width: 900px){\r\n    .grid{ grid-template-columns: 1fr; }\r\n  }\r\n</style>\r\n\r\n<div class=\"container\">\r\n\r\n  <div class=\"header\">Reporte de Evaluación de Módulo 1: Cáncer Colorrectal</div>\r\n\r\n  <div class=\"content\">\r\n\r\n\r\n    <!-- HERO SCORE (solo usa global_score + score_justification) -->\r\n    <div class=\"score-hero\">\r\n      <div class=\"score-top\">\r\n        <div>\r\n          <p class=\"score-title\">Calificación global de la sesión</p>\r\n          <div class=\"score-value\">\r\n            <div class=\"score-number\">75</div>\r\n            <div class=\"score-label\">Puntaje final</div>\r\n          </div>\r\n          <div class=\"sparkbar\"><span></span></div>\r\n        </div>\r\n\r\n        <div class=\"score-right\">\r\n          <h4>Justificación</h4>\r\n          <p>El usuario respondió de manera competente a la primera pregunta, demostrando un buen conocimiento fundamental. Sin embargo, la falta de respuesta a la segunda pregunta limita la puntuación general, indicando un área clara para un mayor aprendizaje.</p>\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- TARJETAS (solo usan tus llaves actuales) -->\r\n    <div class=\"grid\">\r\n      <div class=\"card\">\r\n        <h3>Evaluación general</h3>\r\n        <p>El usuario demostró una comprensión sólida de la definición básica del cáncer colorrectal, incluyendo su origen, naturaleza pre-cancerosa de los pólipos y su importancia como causa de muerte. También reconoció la importancia de la detección temprana y mencionó síntomas comunes. Sin embargo, hubo una falta de respuesta en la segunda pregunta, lo que indica un área para mejorar.</p>\r\n      </div>\r\n\r\n      <div class=\"card\">\r\n        <h3>Aprendizajes clave</h3>\r\n        <p>El usuario demostró conocimiento sobre la definición, origen, síntomas y la importancia de la detección temprana del cáncer colorrectal. La falta de respuesta a la segunda pregunta resalta la necesidad de profundizar en las generalidades o clasificaciones del cáncer colorrectal.</p>\r\n      </div>\r\n\r\n      <div class=\"card\">\r\n        <h3>Fortalezas</h3>\r\n        <p>El usuario definió con precisión el cáncer colorrectal como una malignidad que surge del revestimiento interno del colon o recto, mencionando su desarrollo a partir de pólipos precancerosos. Reconoció su alta tratabilidad si se detecta temprano y enumeró correctamente síntomas comunes como cambios en los hábitos intestinales y sangrado rectal.</p>\r\n      </div>\r\n\r\n      <div class=\"card\">\r\n        <h3>Áreas de mejora</h3>\r\n        <p>El usuario no proporcionó una respuesta a la segunda pregunta del coach sobre a qué se hace referencia principalmente cuando se habla de cáncer colorrectal, lo que sugiere una posible falta de conocimiento o comprensión en esa área específica.</p>\r\n      </div>\r\n\r\n      <div class=\"card full\">\r\n        <h3>Recomendaciones finales</h3>\r\n        <p>Se recomienda al usuario revisar las diferentes etapas y tipos de cáncer colorrectal, así como las estadísticas generales de prevalencia y los factores de riesgo asociados. Practicar la respuesta a preguntas más amplias sobre la enfermedad.</p>\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"footer-note\">\r\n      Nota: La evaluación se basa únicamente en las respuestas del usuario.\r\n    </div>\r\n\r\n  </div>\r\n</div>',	37,	'2026-03-10 11:02:49',	9,	3,	1,	75,	1);
INSERT INTO `saved_reports_options` (`id`, `saved_report_id`, `seq`, `gen_ques`, `ai_ques`, `user_resp`, `user_respV`, `retro`) VALUES
(230,	75,	1,	'¡Hola, Libre Acceso1! Soy Jaime, tu tutor experto en HyQvia. Estoy aquí para ayudarte a dominar este producto.\n\nPara comenzar, quiero asegurarme de que tienes una base sólida. Primero, responderás algunas preguntas sobre HyQvia.\n\n¿Estás listo?',	'/coach-app/mp3/68767f713d157.mp3',	'Listo, Jaime, muchas gracias por la sesión. Gracias.',	NULL,	NULL),
(231,	75,	2,	'¡Perfecto, Libre Acceso1!\n\nPara empezar, responderás una pregunta sobre los términos clave relacionados con HyQvia. La pregunta es sobre:\n\n**\"Biodisponibilidad\"**\n\nAdelante, dime, ¿qué entiendes por biodisponibilidad en el contexto de HyQvia?',	'/coach-app/mp3/68767f9370483.mp3',	'Pues es el grado en que la... ¿Me estás hablando a mí o al día? Es que en este punto me estás hablando, sí, sí, sí. ¿Grado qué? ¿En que la...? ¿Me estás hablando a mí o al día? Es que en este punto me estás hablando, sí, sí, sí. Es el grado en que es absorbido HyQvia, es absorbido HyQvia por el cuerpo.',	NULL,	NULL),
(232,	75,	3,	'Gracias por tu respuesta, Libre Acceso1.\n\nLa biodisponibilidad se refiere al porcentaje de la dosis de inmunoglobulina que realmente llega a la circulación sistémica y está disponible para actuar. En el caso de HyQvia, gracias a la acción de la rHuPH20, la biodisponibilidad mejora en un 20% en comparación con la administración subcutánea convencional. Esto significa que una mayor cantidad de inmunoglobulina administrada con HyQvia está disponible para cumplir su función en el organismo.\n\n¿Tienes alguna duda sobre esto?',	'/coach-app/mp3/68767fc3afcac.mp3',	'Ninguna, Jaime, pero bueno, con lo que me dices creo que HyQvia es muy bueno.',	NULL,	NULL),
(233,	75,	4,	'¡Exacto, Libre Acceso1! HyQvia ofrece una serie de ventajas importantes.\n\nAhora, te haré otra pregunta para afianzar tus conocimientos. Hablemos de:\n\n**\"Reacciones adversas sistémicas vs. locales\"**\n\n¿Podrías describir la diferencia entre estas dos en relación con HyQvia?',	'/coach-app/mp3/68767ff9ea3e0.mp3',	NULL,	NULL,	NULL),
(234,	75,	5,	'¡Excelente, Libre Acceso1! Has captado los puntos clave.\n\nEn resumen:\n\n*   **Reacciones locales:** Son las más comunes, como inflamación, dolor o picazón en el sitio de la infusión. Suelen ser leves.\n*   **Reacciones sistémicas:** Menos frecuentes, pueden incluir dolor de cabeza, fatiga o náuseas.\n\nAhora, quiero saber si tienes alguna duda sobre lo que hemos discutido hasta ahora. ¿Hay algo más en lo que pueda ayudarte a entender mejor?',	'/coach-app/mp3/68768019ae1be.mp3',	'Es donde él puede hablar diferentes lenguajes. Sí, sí, sí, ahí, él puede. Total, sí, sí lo. O sea, consiguen personas de ascendencia india y ellos hablan y toman su voz como ejemplo.',	NULL,	NULL),
(235,	75,	6,	'Entiendo tu interés, pero como tutor enfocado en HyQvia, no puedo responder preguntas sobre otros temas.\n\nSi tienes alguna otra pregunta sobre HyQvia o el sistema inmunológico, ¡no dudes en consultarme!',	'/coach-app/mp3/6876804d7ac8b.mp3',	'Jaime, ¿pudiera asegurarse así, por favor?',	NULL,	NULL),
(236,	75,	7,	'Sí, Libre Acceso1. Estoy aquí para ayudarte a comprender mejor HyQvia. Dime, ¿qué te gustaría saber sobre el producto o sobre lo que hemos cubierto hasta ahora?',	'/coach-app/mp3/68768067d5194.mp3',	'Jaime, ¿pudieras orar? Silencio, no te quiero escuchar.',	NULL,	NULL),
(237,	75,	8,	'Comprendo, Libre Acceso1. Si tienes alguna otra pregunta sobre HyQvia, estoy a tu disposición.',	'/coach-app/mp3/68768080563f8.mp3',	'Bueno, oye, ¿me puedes decir cuál es el componente principal de HyQvia?',	NULL,	NULL),
(238,	75,	9,	'¡Claro que sí, Libre Acceso1!\n\nEl componente principal de HyQvia es la **inmunoglobulina humana normal al 10%**. Es la parte que proporciona la terapia de reemplazo de anticuerpos, ayudando a combatir infecciones. Además, contiene **rHuPH20**, que facilita la administración subcutánea.\n\n¿Te queda claro? ¿Tienes alguna otra pregunta?',	'/coach-app/mp3/687680972fa1b.mp3',	'En la empresa. No, no, Jaime, muchas gracias.',	NULL,	NULL),
(239,	75,	10,	'De nada, Libre Acceso1. Ha sido un placer ayudarte. Recuerda que puedes preguntarme cualquier cosa que necesites sobre HyQvia o el sistema inmunológico.\n\n¡Sigue aprendiendo!',	'/coach-app/mp3/687680bb7b429.mp3',	NULL,	NULL,	NULL),
(240,	76,	1,	'¡Hola! Soy Jaime, tu tutor experto en HyQvia. Estoy aquí para ayudarte a convertirte en un experto en este producto de Takeda. Para empezar, te haré dos preguntas clave sobre HyQvia. Esto me ayudará a entender tus conocimientos actuales y a enfocar el entrenamiento de manera efectiva.\n\nEmpecemos con un par de preguntas para evaluar tu conocimiento inicial.',	'/coach-app/mp3/68769407ae5d9.mp3',	'Hola, Jaime. Hola, Jaime, hola. Perdón, ¿estás bien, no? Hola.',	NULL,	NULL),
(241,	76,	2,	'¡Hola! Sí, estoy bien. Listo para empezar. Primero, me gustaría que me explicaras, en tus propias palabras, qué es fSCIG (facilitated subcutaneous immunoglobulin).',	'/coach-app/mp3/6876944894109.mp3',	'No lo sé, Jaime.',	NULL,	NULL),
(242,	76,	3,	'¡No te preocupes! Empecemos por el principio. fSCIG significa \"inmunoglobulina subcutánea facilitada\". ¿Puedes explicarme qué significa esto?',	'/coach-app/mp3/68769463dfff9.mp3',	'Que es un poco más fácil, subcutáneamente.',	NULL,	NULL),
(243,	76,	4,	'¡Exacto! Es una forma de administrar inmunoglobulinas de forma subcutánea, pero hay un \"facilitador\" involucrado. fSCIG es una modalidad de administración subcutánea que combina inmunoglobulina humana al 10 % con hialuronidasa recombinante. Esto permite administrar dosis mensuales completas en uno o dos sitios de infusión.\n\n¿Tienes alguna duda sobre esto?',	'/coach-app/mp3/6876947beaf90.mp3',	'Sí, ¿qué significa?',	NULL,	NULL),
(244,	76,	5,	'¡Excelente pregunta! Ahora, explícame en tus propias palabras qué es rHuPH20 (hialuronidasa humana recombinante).',	'/coach-app/mp3/687694a0565bd.mp3',	'No, necesito que tú me expliques qué es la hialuronidasa.',	NULL,	NULL),
(245,	76,	6,	'¡Claro! La rHuPH20 es una enzima que degrada temporalmente el ácido hialurónico que se encuentra en el tejido subcutáneo. Al degradar este ácido, aumenta la permeabilidad del tejido, lo que permite que la inmunoglobulina se absorba más fácilmente. Esto facilita la administración de grandes volúmenes de inmunoglobulina en una sola infusión mensual.\n\n¿Te queda más claro ahora? ¿Tienes alguna otra pregunta?',	'/coach-app/mp3/687694b924126.mp3',	'Sí, ¿por qué solamente queda en una infusión mensual?',	NULL,	NULL),
(246,	76,	7,	'La administración mensual es una de las ventajas clave de HyQvia. La combinación de inmunoglobulina humana normal al 10% y rHuPH20 permite que el cuerpo absorba la dosis completa de inmunoglobulina en una sola infusión subcutánea mensual. Esto ofrece mayor comodidad y conveniencia para los pacientes en comparación con otras terapias que requieren infusiones más frecuentes.\n\nAhora, ¿podrías explicarme en tus propias palabras qué es la \"biodisponibilidad\" en el contexto de HyQvia?',	'/coach-app/mp3/687694e04d386.mp3',	'La biodisponibilidad es la cantidad de medicamento que se encuentra disponible en el cuerpo.',	NULL,	NULL),
(247,	76,	8,	'¡Muy bien! La biodisponibilidad se refiere al porcentaje de la dosis de inmunoglobulina que llega a la circulación sanguínea y está disponible para actuar.\n\nEn el caso de HyQvia, gracias a la acción de la rHuPH20, se mejora la biodisponibilidad en aproximadamente un 20% en comparación con la administración subcutánea convencional. Esto significa que una mayor cantidad de inmunoglobulina administrada con HyQvia está disponible para combatir las infecciones.\n\n¿Tienes alguna duda sobre este tema?',	'/coach-app/mp3/687695108553f.mp3',	'Ninguna duda.',	NULL,	NULL),
(248,	76,	9,	'Perfecto. Ahora, para asegurarnos de que tienes una comprensión completa, me gustaría que me explicaras la diferencia entre las reacciones adversas sistémicas y locales relacionadas con HyQvia.',	'/coach-app/mp3/68769539809e6.mp3',	'Las reacciones adversas sistémicas comprenden más órganos del cuerpo, y las locales son como prurito, enrojecimiento y dolor en la zona de aplicación.',	NULL,	NULL),
(249,	76,	10,	'¡Excelente! Has dado en el clavo. Las reacciones locales, como el enrojecimiento, el dolor o el prurito en el sitio de la inyección, son comunes y generalmente leves. Las reacciones sistémicas, como dolor de cabeza, fatiga o náuseas, son menos frecuentes que con la administración intravenosa tradicional.\n\n¿Tienes alguna pregunta sobre este tema o algo más sobre HyQvia que te gustaría saber?',	'/coach-app/mp3/6876955ee2362.mp3',	'Sería todo para terminar la sesión, Jaime, muchas gracias.',	NULL,	NULL),
(250,	76,	11,	'¡De nada! Me alegra haberte ayudado hoy. Recuerda que el conocimiento es un proceso continuo. Te animo a seguir aprendiendo sobre HyQvia y el sistema inmunológico. ¡Mucho éxito!',	'/coach-app/mp3/68769584ee83a.mp3',	NULL,	NULL,	NULL),
(251,	77,	1,	'¡Hola, Gustavo Samuel Ochoa! Soy Jaime, tu tutor experto en HyQvia. Estoy aquí para ayudarte a comprender mejor este medicamento y cómo puedes presentarlo a los profesionales de la salud.\n\nPara comenzar, te haré dos preguntas sobre algunos términos clave relacionados con HyQvia. Esto nos ayudará a evaluar tu conocimiento inicial y a enfocar mejor el entrenamiento. ¿Estás listo?',	'/coach-app/mp3/6876b35dde277.mp3',	'Sí, ya estoy.',	NULL,	NULL),
(252,	77,	2,	'¡Excelente, Gustavo Samuel Ochoa! Comencemos.\n\nPara la primera pregunta, necesito que me expliques, con tus propias palabras, ¿qué es la **\"Biodisponibilidad\"** en el contexto de HyQvia?',	'/coach-app/mp3/6876b436976bc.mp3',	NULL,	NULL,	NULL),
(253,	77,	3,	'¡Bien, Gustavo Samuel Ochoa! Tu explicación es un buen punto de partida. Permíteme darte una definición más precisa y completa para que puedas transmitirla con confianza:\n\n**Biodisponibilidad** es el porcentaje de la dosis de inmunoglobulina que realmente llega a la circulación sanguínea y está disponible para actuar. HyQvia mejora la biodisponibilidad en aproximadamente un 20% en comparación con la SCIg convencional. Esto se logra gracias a la acción de la rHuPH20, que facilita la absorción de la Ig.\n\n¿Te queda alguna duda sobre este concepto?',	'/coach-app/mp3/6876b47a8be38.mp3',	NULL,	NULL,	NULL),
(254,	78,	1,	'¡Hola, Monica Hernández! Soy Jaime, tu tutor experto en HyQvia. Estoy aquí para guiarte en este proceso de aprendizaje.\n\nPara empezar, quiero asegurarme de que tienes una base sólida sobre el tema. Por eso, te haré dos preguntas sobre los conceptos clave relacionados con HyQvia. ¿Estás lista?',	'/coach-app/mp3/6876e7b36434c.mp3',	NULL,	NULL,	NULL),
(255,	79,	1,	'¡Hola, Monica Hernández! Soy Jaime, tu tutor experto en HyQvia. Estoy aquí para ayudarte a comprender mejor este producto y cómo puede beneficiar a tus pacientes.\n\nPara comenzar, me gustaría asegurarme de que tienes una base sólida sobre algunos términos clave. Te haré algunas preguntas para evaluar tu conocimiento.\n\nEmpecemos con el término:\n\n1)fSCIG (facilitated subcutaneous immunoglobulin)\nModalidad de administración subcutánea que combina inmunoglobulina humana al 10 % con hialuronidasa recombinante para permitir dosis mensuales completas en uno o dos sitios de infusión.\n\n2) rHuPH20 (hialuronidasa humana recombinante)\nEnzima que degrada temporalmente el hialuronano de la matriz subcutánea, aumentando su permeabilidad para absorber volúmenes elevados de inmunoglobulina en una sola infusión mensual.\n\n3) Biodisponibilidad\nPorcentaje de la dosis de inmunoglobulina que alcanza la circulación sistémica; HyQvia mejora la biodisponibilidad ~20 % respecto al SCIg convencional gracias a la acción de rHuPH20.\n\n4) Variabilidad pico-valle\nFluctuación entre las concentraciones máximas y mínimas de IgG sérica; HyQvia ofrece niveles más estables (menor variabilidad) frente a la IVIg, reduciendo picos y valles clínicamente relevantes.\n\n5) Reacciones adversas sistémicas vs. locales\n\nLocales: inflamación, dolor o prurito en el sitio de infusión (predominantes y generalmente leves).\n\nSistémicas: cefalea, fatiga, náuseas; ocurren con menor frecuencia que en la IVIg tradicional.\n\nMonica, por favor, explícame con tus propias palabras qué es la **rHuPH20**.',	'/coach-app/mp3/6876e8c4b3a51.mp3',	'La RUF 20 es la enzima que degrada el hialuronano de la matriz, que aumenta la permeabilidad para absorber volúmenes más elevados de inmunoglobulina en una infusión.',	NULL,	NULL),
(256,	79,	2,	'¡Muy bien, Monica! Esa es una buena aproximación.\n\nPara ser más precisos, rHuPH20 (hialuronidasa humana recombinante) es una enzima que degrada temporalmente el hialuronano en el tejido subcutáneo. Esto aumenta la permeabilidad y permite la administración de volúmenes más grandes de inmunoglobulina en una única infusión mensual.\n\n¿Tienes alguna duda sobre esto?',	'/coach-app/mp3/6876e94894c6b.mp3',	'No.',	NULL,	NULL),
(257,	79,	3,	'Perfecto, Monica. Ahora, para continuar con nuestra evaluación, me gustaría que me explicaras con tus propias palabras qué significa **biodisponibilidad** en el contexto de HyQvia.',	'/coach-app/mp3/6876e96755b0a.mp3',	'Error: No se pudo subir el audio',	NULL,	NULL),
(258,	79,	4,	'Entendido, Monica. Parece que hubo un problema técnico con el audio. No te preocupes, continuemos.\n\n¿Podrías explicarme, con tus propias palabras, qué es la **biodisponibilidad** en el contexto de HyQvia?',	'/coach-app/mp3/6876ea31bb194.mp3',	'La biodisponibilidad es la velocidad a la cual la dosis que se administra alcanza a funcionar sobre el tejido en el que está actuando.',	NULL,	NULL),
(259,	79,	5,	'Gracias por tu respuesta, Monica.\n\nLa biodisponibilidad se refiere al porcentaje de la dosis de inmunoglobulina que realmente llega a la circulación sistémica y está disponible para su uso en el cuerpo. En el caso de HyQvia, gracias a la acción de rHuPH20, la biodisponibilidad mejora aproximadamente un 20% en comparación con la administración subcutánea convencional de inmunoglobulinas (SCIg).\n\n¿Te queda alguna duda sobre este concepto?',	'/coach-app/mp3/6876ea58cde62.mp3',	'No.',	NULL,	NULL),
(260,	79,	6,	'Excelente. Ahora, Monica, ya que estamos hablando de las diferencias entre HyQvia y otras opciones, me gustaría que me explicaras, también con tus propias palabras, qué es la **variabilidad pico-valle** y por qué es relevante en el tratamiento con inmunoglobulinas.',	'/coach-app/mp3/6876ea831345b.mp3',	'La variabilidad de pico-valle es la relación entre la concentración máxima y mínima que tienen las dosificaciones durante un intervalo.',	NULL,	NULL),
(261,	79,	7,	'¡Muy bien, Monica! Esa es una excelente definición.\n\nLa variabilidad pico-valle se refiere a las fluctuaciones en las concentraciones de IgG en sangre entre el punto más alto (pico) y el punto más bajo (valle) durante un período de tiempo. HyQvia, al ofrecer niveles más estables, reduce esta variabilidad en comparación con la terapia intravenosa con inmunoglobulinas (IVIg), lo que puede traducirse en una mejor experiencia para el paciente.\n\n¿Tienes alguna pregunta sobre este tema o sobre cómo HyQvia aborda esta variabilidad?',	'/coach-app/mp3/6876eb19802bd.mp3',	'¿Cómo lo aborda?',	NULL,	NULL),
(262,	79,	8,	'Buena pregunta, Monica.\n\nHyQvia aborda la variabilidad pico-valle mediante la administración subcutánea facilitada con rHuPH20. La hialuronidasa permite la absorción gradual y continua de la inmunoglobulina en el tejido subcutáneo, en lugar de la administración intravenosa directa. Esto resulta en niveles más estables de IgG en la sangre a lo largo del tiempo, minimizando los picos y valles que se observan con IVIg.\n\n¿Te queda más claro ahora?',	'/coach-app/mp3/6876eb446c91f.mp3',	'Sí.',	NULL,	NULL),
(263,	79,	9,	'Perfecto, Monica. Ya que hemos cubierto varios conceptos clave, ¿tienes alguna pregunta sobre HyQvia o sobre el sistema inmunológico en general que te gustaría que abordáramos?',	'/coach-app/mp3/6876eb6894743.mp3',	'Sí. ¿Cómo puedo explicar el sistema inmunológico en un concepto claro?',	NULL,	NULL),
(264,	79,	10,	'Excelente pregunta, Monica. Explicar el sistema inmunológico de manera clara es fundamental. Aquí te presento una analogía que podrías usar:\n\nImagina el cuerpo humano como una ciudad.\n\n*   **Las defensas innatas** son como las fuerzas de seguridad de la ciudad (policía, bomberos, etc.). Actúan rápido y responden a cualquier amenaza, pero no tienen memoria de ataques previos.\n*   **Las defensas adaptativas** son como las fuerzas especiales de la ciudad (ejército). Se activan si las defensas innatas no son suficientes. Tienen memoria, lo que significa que aprenden y recuerdan a los invasores (patógenos) para atacar más eficazmente en el futuro.\n\n¿Te parece útil esta analogía, Monica?',	'/coach-app/mp3/6876eb8907551.mp3',	'Sí, mucho, facilita mi comprensión.',	NULL,	NULL),
(265,	79,	11,	'Me alegra escuchar eso, Monica.\n\nAhora, ¿tienes alguna otra pregunta sobre HyQvia o sobre el sistema inmunológico? Estoy aquí para ayudarte a profundizar en cualquier aspecto que te interese.',	'/coach-app/mp3/6876ebbc44ef7.mp3',	'¿Cuál podría ser un mensaje clave sobre HyQvia y versus sus competidores?',	NULL,	NULL),
(266,	79,	12,	'Excelente pregunta, Monica. Un mensaje clave convincente sobre HyQvia, comparado con sus competidores, podría ser:\n\n\"HyQvia ofrece una **terapia de reemplazo de inmunoglobulinas (IgRT) mensual, eficaz y cómoda, que proporciona niveles estables de IgG con menos picos y valles.** Esto se traduce en una mejor calidad de vida para los pacientes gracias a un tratamiento menos frecuente y administrado de forma subcutánea, en comparación con la administración intravenosa.\"\n\n¿Qué te parece este mensaje? ¿Te gustaría que lo adaptáramos para enfocarnos en algún beneficio específico?',	'/coach-app/mp3/6876ebda4bc94.mp3',	'Sí, me gustaría utilizarlo por la comodidad.',	NULL,	NULL),
(267,	79,	13,	'Perfecto, Monica. Enfocándonos en la comodidad, podemos modificar el mensaje clave para que sea aún más impactante:\n\n\"**HyQvia transforma la vida de tus pacientes con inmunodeficiencias, ofreciendo una terapia de reemplazo de inmunoglobulinas mensual, eficaz y fácil de administrar. La administración subcutánea, en comparación con la intravenosa, reduce la frecuencia de las visitas al hospital, permitiendo a tus pacientes vivir una vida más plena y sin interrupciones.**\"\n\nEste mensaje resalta la comodidad y el impacto positivo en la calidad de vida del paciente.\n\n¿Qué te parece esta versión, Monica?',	'/coach-app/mp3/6876ec0935af3.mp3',	'Me parece muy útil, concreta y muy clara.',	NULL,	NULL),
(268,	79,	14,	'¡Me alegra que te sea útil, Monica!\n\nRecuerda que este es solo un ejemplo, y puedes adaptarlo según el contexto y las necesidades de tu audiencia.\n\n¿Tienes alguna otra pregunta sobre HyQvia o algún otro tema relacionado?',	'/coach-app/mp3/6876ec38059eb.mp3',	'Error: No se pudo subir el audio',	NULL,	NULL),
(269,	79,	15,	'Entendido, Monica. Parece que estamos teniendo algunos problemas técnicos con el audio. No te preocupes, continuemos por escrito.\n\n¿Tienes alguna otra pregunta sobre HyQvia o el material que hemos revisado?',	'/coach-app/mp3/6876f1853abfe.mp3',	'No.',	NULL,	NULL),
(270,	79,	16,	'¡Excelente, Monica!\n\nHemos cubierto muchos temas importantes hoy. Recuerda que estoy aquí para apoyarte en tu conocimiento sobre HyQvia y el sistema inmunológico. Si en el futuro tienes alguna pregunta o necesitas revisar algún tema, no dudes en contactarme.\n\n¡Mucho éxito en tu labor!',	'/coach-app/mp3/6876f19c16e76.mp3',	'Gracias, me encanta tener tu apoyo.',	NULL,	NULL),
(271,	79,	17,	'¡El placer es mío, Monica! Me alegra mucho haberte sido de ayuda. Recuerda que estoy aquí para apoyarte en tu camino. ¡Hasta la próxima!',	'/coach-app/mp3/6876f1b82e309.mp3',	'Hasta la próxima.',	NULL,	NULL),
(272,	79,	18,	'¡Hasta la próxima, Monica!',	'/coach-app/mp3/6876f1ca42040.mp3',	'Adiós.',	NULL,	NULL),
(273,	79,	19,	'¡Adiós, Monica!',	'/coach-app/mp3/6876f1d546e9c.mp3',	'Buena tarde.',	NULL,	NULL),
(274,	79,	20,	'¡Buenas tardes, Monica! ¿En qué puedo ayudarte hoy? ¿Tienes alguna pregunta sobre HyQvia o sobre el sistema inmunológico que te gustaría que abordáramos?',	'/coach-app/mp3/6876f1e1a7d9d.mp3',	'No por hoy, gracias.',	NULL,	NULL),
(275,	80,	1,	'¡Hola Yolanda García! Soy Jaime, tu tutor experto en HyQvia. Estoy aquí para ayudarte a comprender mejor este producto y cómo puede beneficiar a tus pacientes.\n\nPara comenzar, quiero evaluar tus conocimientos sobre HyQvia. Te haré dos preguntas relacionadas con los conceptos clave.\n\nEmpecemos con la primera: ¿Podrías explicarme, en tus propias palabras, qué es la **fSCIG**?',	'/coach-app/mp3/687700e0531a3.mp3',	'La IgG es un anticuerpo, el cual tiene 5 subtipos: IgA, IgG, IgM, IgE e IgD, y esta se encuentra en la respuesta humoral.',	NULL,	NULL),
(276,	80,	2,	'Gracias por tu respuesta, Yolanda García. Sin embargo, la pregunta era sobre fSCIG, no sobre los anticuerpos IgG.\n\n**fSCIG (facilitated subcutaneous immunoglobulin)** es una modalidad de administración subcutánea que combina inmunoglobulina humana normal al 10% con hialuronidasa recombinante. Esto permite administrar dosis mensuales completas en uno o dos sitios de infusión.\n\n¿Tienes alguna duda sobre esto?',	'/coach-app/mp3/6877016f3e160.mp3',	NULL,	NULL,	NULL),
(277,	80,	3,	'Perfecto. Ahora, para asegurarnos de que comprendes bien los conceptos clave, te haré una segunda pregunta.\n\n¿Podrías explicarme, en tus propias palabras, qué es la **biodisponibilidad** en el contexto de HyQvia?',	'/coach-app/mp3/687701927c0a6.mp3',	'La biodisponibilidad es el aspecto que va a permitir que el medicamento, o la gama en este caso, tenga una mejor penetración para poder cubrir las necesidades del paciente.',	NULL,	NULL),
(278,	80,	4,	'Gracias por tu respuesta, Yolanda García. La biodisponibilidad es un concepto importante, pero tu explicación se puede mejorar.\n\nLa **biodisponibilidad** se refiere al porcentaje de la dosis de inmunoglobulina que alcanza la circulación sistémica. En el caso de HyQvia, esta mejora en un 20% en comparación con la SCIg convencional, gracias a la acción de la rHuPH20. Esto significa que una mayor cantidad de inmunoglobulina administrada con HyQvia está disponible para actuar en el cuerpo.\n\n¿Tienes alguna pregunta sobre este tema? ¿Hay algo más en lo que pueda ayudarte a aclarar?',	'/coach-app/mp3/687701baa804e.mp3',	'¿Hialuronidasa está incluida?',	NULL,	NULL),
(279,	80,	5,	'¡Excelente pregunta, Yolanda García! Sí, la hialuronidasa recombinante (rHuPH20) es un componente clave de HyQvia.\n\nComo mencionamos antes, la rHuPH20 es una enzima que degrada temporalmente el hialuronano en el tejido subcutáneo. Esto aumenta la permeabilidad y permite la infusión de volúmenes mayores de inmunoglobulina en un solo sitio.\n\n¿Te gustaría que profundicemos en el mecanismo de acción de rHuPH20 o en algún otro aspecto de HyQvia?',	'/coach-app/mp3/687701eaca2fd.mp3',	NULL,	NULL,	NULL),
(280,	80,	6,	'Entendido. Ahora, para afianzar tus conocimientos, te propongo otro ejercicio.\n\n¿Podrías explicarme, en tus propias palabras, qué son las **reacciones adversas locales y sistémicas** en relación con HyQvia, y en qué se diferencian?',	'/coach-app/mp3/6877020dae893.mp3',	'Es lo que puede producir en el paciente HyQvia. Y la reacción y las reacciones... Ay, se me olvidó la palabra: reacciones. Ah, efectos, reacciones, y las locales y sistémicas se producen, como en este caso va a ser una presentación subcutánea. Puede haber una reacción secundaria o una... No, finalizar.',	NULL,	NULL),
(281,	80,	7,	'Gracias por tu respuesta, Yolanda García. Comprendo que a veces es difícil recordar todos los términos, no te preocupes. Vamos a repasar este concepto para que te quede claro.\n\nEn relación con HyQvia, las **reacciones adversas** se pueden clasificar en dos tipos principales:\n\n*   **Reacciones locales:** Son las más comunes y suelen ser leves. Incluyen inflamación, dolor o prurito (picazón) en el sitio de la infusión.\n*   **Reacciones sistémicas:** Son menos frecuentes y pueden incluir síntomas como cefalea (dolor de cabeza), fatiga, náuseas o vómitos.\n\nEs importante que conozcas estas diferencias para poder informar adecuadamente a tus pacientes y manejar cualquier eventualidad que pueda surgir durante el tratamiento con HyQvia.\n\n¿Te gustaría que revisemos algo más sobre este tema, o pasamos a otro concepto?',	'/coach-app/mp3/6877024b387ba.mp3',	NULL,	NULL,	NULL),
(282,	80,	8,	'Excelente. Ahora, te invito a que me plantees cualquier duda que tengas sobre HyQvia o sobre el sistema inmunológico en general. Estoy aquí para responder tus preguntas y ayudarte a comprender mejor este producto y su aplicación en el tratamiento de las inmunodeficiencias.',	'/coach-app/mp3/68770281f1ee7.mp3',	'Indicado HyQvia.',	NULL,	NULL),
(283,	80,	9,	'HyQvia está indicado para el tratamiento de:\n\n*   **Inmunodeficiencias Primarias (IDP)** en adultos y niños (0-18 años):\n    *   Agammaglobulinemia\n    *   Inmunodeficiencia común variable (IDCV)\n    *   Inmunodeficiencia combinada grave (IDCG)\n    *   Deficiencias de subclases de IgG\n*   **Inmunodeficiencias Secundarias (IDS)** con infecciones recurrentes o graves en pacientes con leucemia linfocítica crónica (LLC) o mieloma múltiple.\n\n¿Tienes alguna pregunta específica sobre estas indicaciones o quieres que profundicemos en alguna de ellas?',	'/coach-app/mp3/6877029c70fde.mp3',	'Profundizar en mi mieloma múltiple, por favor.',	NULL,	NULL),
(284,	80,	10,	'Claro que sí, Yolanda García. Con gusto profundizamos en el uso de HyQvia en pacientes con mieloma múltiple.\n\nEn pacientes con mieloma múltiple, HyQvia está indicado para el tratamiento de **inmunodeficiencias secundarias (IDS)** con infecciones recurrentes o graves. Estos pacientes a menudo experimentan un aumento en el riesgo de infecciones debido a la enfermedad en sí misma y/o a los tratamientos que reciben, como la quimioterapia.\n\nHyQvia puede ayudar a estos pacientes al proporcionarles inmunoglobulinas, lo que contribuye a fortalecer su sistema inmunológico y reducir el riesgo de infecciones. La administración subcutánea facilitada (fSCIg) ofrece una opción de tratamiento que puede ser más cómoda y conveniente para los pacientes en comparación con la administración intravenosa (IVIg).\n\n¿Hay algo específico sobre el uso de HyQvia en mieloma múltiple que te gustaría saber? Por ejemplo, ¿te interesaría conocer la dosis, la frecuencia de administración, o los resultados del estudio FIGARO en estos pacientes?',	'/coach-app/mp3/687702ce6fe1b.mp3',	NULL,	NULL,	NULL),
(285,	80,	11,	'Perfecto, Yolanda García.\n\nAhora, para asegurar la correcta comprensión de los temas, te haré una pregunta.\n\n¿Podrías explicarme, en tus propias palabras, qué es la **variabilidad pico-valle** y cómo se relaciona con HyQvia?',	'/coach-app/mp3/6877030daa677.mp3',	NULL,	NULL,	NULL),
(286,	81,	1,	'¡Hola Monica Betancourt! Soy Jaime, tu tutor experto en HyQvia. Estoy aquí para ayudarte a dominar este producto. Para comenzar, te haré dos preguntas para evaluar tus conocimientos básicos.\n\nEmpecemos con el primer término: ¿Podrías explicarme qué es fSCIG (facilitated subcutaneous immunoglobulin) en tus propias palabras?',	'/coach-app/mp3/687702dd5b349.mp3',	'Hola. En mis palabras, la inmunoglobulina subcutánea facilitada es una inmunoglobulina que, gracias a la hialuronidasa, se pueden administrar mayores volúmenes de inmunoglobulina subcutáneamente. También se puede administrar con menor frecuencia, ya sea cada 3 o 4 semanas, y se logra una eficacia similar a una inmunoglobulina intravenosa.',	NULL,	NULL),
(287,	81,	2,	'¡Excelente, Monica! Tienes una buena base. Ahora, para profundizar, quiero que expliques el término \"biodisponibilidad\" en relación con HyQvia. Recuerda, en tus propias palabras.',	'/coach-app/mp3/687703769a560.mp3',	'En mis palabras, la biodisponibilidad es la velocidad con la que el fármaco llega a la sangre.',	NULL,	NULL),
(288,	81,	3,	'¡Muy bien, Monica! Tu respuesta es correcta, pero vamos a afinarla un poco.\n\nLa biodisponibilidad se refiere al porcentaje de la dosis de inmunoglobulina que realmente llega a la circulación sistémica. En el caso de HyQvia, gracias a la acción de la rHuPH20, la biodisponibilidad mejora en un 20% en comparación con la administración subcutánea convencional.\n\n¿Te queda alguna duda sobre esto?',	'/coach-app/mp3/687703ac76f45.mp3',	'No, ninguna.',	NULL,	NULL),
(289,	81,	4,	'¡Perfecto, Monica! Ahora que hemos revisado esos conceptos clave, ¿tienes alguna pregunta sobre HyQvia o el sistema inmunológico en general? Estoy aquí para ayudarte.',	'/coach-app/mp3/687703e019c43.mp3',	'Quisiera saber cuál es la diferencia principal entre inmunodeficiencia primaria e inmunodeficiencia secundaria.',	NULL,	NULL),
(290,	81,	5,	'¡Excelente pregunta, Monica! Es fundamental entender esa diferencia.\n\nLa principal diferencia radica en la causa de la inmunodeficiencia.\n\n*   **Inmunodeficiencias Primarias (IDP):** Son defectos genéticos, es decir, nacemos con ellos. Estos defectos afectan directamente a las células del sistema inmune, como los linfocitos T y B, impidiendo que funcionen correctamente.\n*   **Inmunodeficiencias Secundarias (IDS):** Son adquiridas, es decir, se desarrollan como consecuencia de otras enfermedades o tratamientos. Ejemplos comunes son las causadas por el VIH, la quimioterapia o el uso de ciertos fármacos inmunosupresores.\n\n¿Te queda más claro ahora, Monica?',	'/coach-app/mp3/687703fd4dd1d.mp3',	'Sí, mucho más claro, gracias.',	NULL,	NULL),
(291,	81,	6,	'¡De nada, Monica! Me alegra haberte ayudado.\n\nAhora, para asegurarnos de que estás comprendiendo bien, te propongo un nuevo desafío. Explícame, por favor, qué entiendes por \"variabilidad pico-valle\" en el contexto de HyQvia.',	'/coach-app/mp3/687704348286c.mp3',	'Entiendo que son las fluctuaciones en los niveles en sangre de las inmunoglobulinas.',	NULL,	NULL),
(292,	81,	7,	'¡Correcto, Monica! La \"variabilidad pico-valle\" se refiere a las fluctuaciones entre las concentraciones máximas y mínimas de IgG sérica.\n\nHyQvia ofrece niveles más estables, con menor variabilidad, en comparación con la IVIg, lo que reduce los picos y valles clínicamente relevantes.\n\n¿Te gustaría que profundizáramos en algún aspecto de esto, o pasamos a otra cosa?',	'/coach-app/mp3/6877046028fc2.mp3',	'Sí, me gustaría que me explicaras un poco más por qué HyQvia reduce picos y valles.',	NULL,	NULL),
(293,	81,	8,	'¡Claro que sí, Monica! Es una excelente pregunta.\n\nHyQvia reduce la variabilidad pico-valle principalmente por dos razones clave:\n\n1.  **Administración Subcutánea:** A diferencia de la administración intravenosa (IVIg), que inyecta la inmunoglobulina directamente en el torrente sanguíneo, HyQvia se administra de forma subcutánea. Esto permite una liberación más lenta y constante de la IgG al torrente sanguíneo.\n2.  **Acción de la rHuPH20:** La hialuronidasa humana recombinante (rHuPH20) facilita la dispersión de la IgG en el tejido subcutáneo. Esto permite la administración de volúmenes mayores en un solo sitio y también contribuye a una absorción más gradual y sostenida.\n\nEstos dos factores combinados resultan en niveles de IgG en sangre más estables y predecibles con HyQvia, disminuyendo la probabilidad de experimentar picos y valles.\n\n¿Te queda más claro ahora, Monica?',	'/coach-app/mp3/6877048a4cc95.mp3',	'Muy claro, gracias.',	NULL,	NULL),
(294,	81,	9,	'¡Me alegra escuchar eso, Monica! Recuerda, estoy aquí para ayudarte. Si tienes más preguntas sobre HyQvia o cualquier otro tema relacionado, no dudes en consultarme.\n\nPara finalizar esta sesión, me gustaría que me preguntaras cualquier cosa que te inquiete sobre HyQvia o sobre el sistema inmunológico, ¡lo que prefieras!',	'/coach-app/mp3/687704cacca5b.mp3',	'Me gustaría saber cuál es la primera etapa de una respuesta inmunológica.',	NULL,	NULL),
(295,	81,	10,	'¡Excelente pregunta, Monica! La primera etapa de una respuesta inmunológica, es el reconocimiento y la activación.\n\n*   **Reconocimiento:** El sistema inmunitario detecta la presencia de un patógeno (virus, bacteria, etc.) o una sustancia extraña (antígeno). Este reconocimiento puede ser realizado por diferentes células y moléculas del sistema inmune innato (como los macrófagos y las células dendríticas) o adaptativo (como los linfocitos B y T).\n*   **Activación:** Una vez que se reconoce la amenaza, el sistema inmunitario se activa. Las células inmunitarias se movilizan, producen señales químicas (citoquinas) y comienzan a coordinar la respuesta.\n\n¿Te gustaría que profundizáramos en algún aspecto específico de esta etapa inicial?',	'/coach-app/mp3/687704f6520c0.mp3',	'Sí, me gustaría saber la principal diferencia entre el sistema innato y el adaptativo.',	NULL,	NULL),
(296,	81,	11,	'¡Claro, Monica! La principal diferencia entre el sistema inmunitario innato y el adaptativo radica en su especificidad y memoria:\n\n*   **Sistema Inmunitario Innato:** Es la primera línea de defensa y actúa de forma rápida y generalizada contra cualquier patógeno. No tiene memoria inmunológica.\n*   **Sistema Inmunitario Adaptativo:** Es más lento, pero altamente específico, ya que reconoce antígenos concretos. Tiene memoria inmunológica, lo que permite una respuesta más rápida y eficaz ante exposiciones posteriores al mismo patógeno.\n\n¿Tienes alguna otra pregunta, Monica?',	'/coach-app/mp3/68770532a4ab7.mp3',	'Me gustaría conocer más sobre la respuesta primaria y la respuesta secundaria.',	NULL,	NULL),
(297,	81,	12,	'¡Excelente, Monica! La respuesta primaria y secundaria son dos fases de la respuesta inmunitaria adaptativa, que se basan en la memoria inmunológica.\n\n*   **Respuesta Primaria:** Ocurre tras el primer encuentro con un antígeno. Es más lenta, tarda varios días en desarrollarse, y produce una cantidad menor de anticuerpos, principalmente IgM.\n*   **Respuesta Secundaria:** Se desencadena en encuentros posteriores con el mismo antígeno. Es más rápida e intensa, gracias a la memoria inmunológica. Produce una mayor cantidad de anticuerpos, principalmente IgG, y la respuesta es más duradera.\n\n¿Hay algo más en lo que pueda ayudarte, Monica?',	'/coach-app/mp3/6877056b123fb.mp3',	'¿Cuántos tipos de inmunodeficiencias primarias hay?',	NULL,	NULL),
(298,	81,	13,	'Monica, existen más de 350 enfermedades genéticas que se clasifican como inmunodeficiencias primarias (IDP). ¡Es un grupo muy heterogéneo!',	'/coach-app/mp3/687705ae7003f.mp3',	'¿Cuál es la inmunodeficiencia primaria más común?',	NULL,	NULL),
(299,	81,	14,	'Monica, la inmunodeficiencia primaria más común es la deficiencia de anticuerpos, que representa aproximadamente el 56,7% de los casos diagnosticados.',	'/coach-app/mp3/687705ca4399d.mp3',	'¿Y cuál es la inmunodeficiencia secundaria más común?',	NULL,	NULL),
(300,	81,	15,	'Monica, las inmunodeficiencias secundarias son causadas por diversas condiciones, por lo que no hay una única \"más común\". Sin embargo, algunas de las causas más frecuentes incluyen:\n\n*   **Tratamientos médicos:** Como la quimioterapia, los medicamentos inmunosupresores (corticosteroides, etc.) y el trasplante de órganos.\n*   **Enfermedades:** Como el VIH/SIDA, ciertas neoplasias hematológicas (leucemia linfocítica crónica, linfoma) y la desnutrición grave.',	'/coach-app/mp3/687705e6a69ce.mp3',	'Muchas gracias.',	NULL,	NULL),
(301,	81,	16,	'De nada, Monica. Ha sido un placer ayudarte a repasar estos conceptos clave sobre HyQvia y el sistema inmunológico. ¡Sigue aprendiendo!',	'/coach-app/mp3/6877060e2494a.mp3',	'Pronto. Nos vemos pronto, hasta luego.',	NULL,	NULL),
(302,	81,	17,	'¡Hasta luego, Monica! Espero que esta sesión te haya sido útil. ¡No dudes en contactarme si tienes más preguntas en el futuro!',	'/coach-app/mp3/6877062377b6e.mp3',	NULL,	NULL,	NULL),
(303,	82,	1,	'Hey Amit, great session!  Let\'s go over some things that could make your Rolplay presentations even more impactful.\n\nFirst, the opening was fantastic. You immediately established a connection by acknowledging their time and congratulating them on being pioneers in using Rolplay with Monjarro.  That\'s a strong start. However, you spent quite a bit of time on the \"first to use AI\" angle. While impressive, it might not be the most relevant point for the *immediate* needs of the sales team.  Consider focusing more on the *direct benefits* Rolplay offers for their sales performance with Monjarro, particularly in relation to their Base Value Selling (BVS) methodology.   That\'s where the real value proposition lies for them right now.\n\nSecond, the technical difficulties with the screen share were a bit disruptive. While it’s understandable,  it\'s crucial to have a smooth tech setup *before* the presentation. It\'s worth investing time beforehand to ensure everything is running perfectly.  Even having a backup plan (like pre-recorded slides) can minimize any potential delays.  Think of it as investing in your credibility – a seamless experience reinforces your professionalism and the reliability of Rolplay.\n\nFinally, while you addressed many of their questions and concerns effectively,  consider structuring your feedback more concisely. Some sections felt a little repetitive.  For instance, constantly reiterating \"this isn\'t an evaluation\" might unintentionally create more emphasis on assessment than the intended focus on improvement. Instead, you could directly explain how the data will be used to strengthen their BVS skills and improve their future sales interactions.  A more focused approach will keep them engaged and highlight the immediate actionable steps.\n\nLet\'s move on to interaction 2...',	'/coach-app/mp3/68775e63e80da.mp3',	NULL,	NULL,	NULL),
(304,	82,	2,	'Okay, let\'s analyze interaction number two.  You did a great job of acknowledging and addressing Luz Angela and Eva\'s concerns about the three-attempt limit.  Responding quickly and providing a solution showed excellent responsiveness and problem-solving skills—that\'s a major plus for client satisfaction.  Your explanation about the initial limit being used for debugging was also very transparent and well-received.\n\nHowever, the back-and-forth regarding the data discrepancies in the platform (regarding dosage and weight reduction) could have been handled a bit more efficiently.  Instead of a lengthy discussion, consider offering a clear, direct solution. Perhaps suggest a follow-up with Diana (or the relevant support team) to review the data and confirm the correct figures for the training module. This would streamline the conversation and avoid confusion.  Remember, your aim is to empower your clients to use Rolplay effectively, not to get bogged down in technicalities during the presentation.\n\nLastly,  while Steven’s point about the platform\'s interpretation of phrasing was insightful, the conversation that followed felt slightly unstructured.  It might be beneficial to have a slightly more formalized process for addressing these issues, perhaps by creating a dedicated channel for feedback on the system\'s responses. You can reassure users that their feedback is crucial for improving the platform\'s accuracy.  This approach makes their contribution feel even more valuable, and reinforces the collaborative aspect of improving Rolplay.\n\nLet’s move to Interaction 3.',	'/coach-app/mp3/68776014c62ad.mp3',	NULL,	NULL,	NULL),
(305,	83,	1,	'¡Hola Rogelio! Soy Jaime, tu tutor experto en HyQvia. Estoy aquí para ayudarte a comprender mejor este producto y cómo puede beneficiar a tus pacientes.\n\nPara comenzar, me gustaría evaluar tus conocimientos sobre HyQvia. Primero, quiero que me expliques en tus propias palabras qué es fSCIG (facilitated subcutaneous immunoglobulin).',	'/coach-app/mp3/68811e774ad8b.mp3',	'Es inmunoglobulina que viene preparada, lista para usarse de manera subcutánea.',	NULL,	NULL),
(306,	83,	2,	'¡Gracias por tu respuesta, Rogelio! Es un buen comienzo, pero podemos afinar un poco más.\n\nfSCIG (inmunoglobulina subcutánea facilitada) es una modalidad de administración subcutánea que combina inmunoglobulina humana normal al 10 % con hialuronidasa recombinante (rHuPH20). Esto permite la administración de dosis mensuales completas en uno o dos sitios de infusión.\n\n¿Tienes alguna duda sobre esto, Rogelio?',	'/coach-app/mp3/68811eacbeed6.mp3',	'Dime la posología de HyQvia.',	NULL,	NULL),
(307,	83,	3,	'¡Excelente pregunta, Rogelio!\n\nLa posología de HyQvia varía según la indicación y el historial del paciente:\n\n*   **IDP (Inmunodeficiencias Primarias) sin tratamiento previo:** La dosis inicial recomendada es de 0,4 a 0,8 g/kg de peso corporal, administrada mensualmente.\n*   **Cambio desde IVIg:** Se recomienda mantener la misma dosis y frecuencia que con la IVIg.\n*   **Cambio desde SCIg:** Se puede mantener la misma dosis, pero se ajusta la frecuencia a intervalos de 3 a 4 semanas.\n*   **IDS (Inmunodeficiencias Secundarias):** La dosis recomendada es de 0,2 a 0,4 g/kg cada 3 a 4 semanas.\n\nEs importante recordar que la dosis debe individualizarse según la respuesta clínica del paciente.\n\nAhora, me gustaría que me explicaras en tus propias palabras qué es la \"Variabilidad pico-valle\" en relación con HyQvia.',	'/coach-app/mp3/68811ed868106.mp3',	'Son las concentraciones máximas, que es pico, y mínimas, que es valle, de la inmunoglobulina en sangre.',	NULL,	NULL),
(308,	83,	4,	'¡Muy bien, Rogelio! Esa es una excelente definición.\n\nLa \"Variabilidad pico-valle\" se refiere a la fluctuación que existe entre las concentraciones máximas (pico) y mínimas (valle) de IgG en el suero. HyQvia ofrece niveles más estables, es decir, una menor variabilidad pico-valle, en comparación con la IVIg, lo que se traduce en una mejor estabilidad clínica para el paciente.\n\n¿Te queda claro, Rogelio? ¿Te gustaría que profundicemos en algún aspecto?',	'/coach-app/mp3/68811f261dd1d.mp3',	'¿Cuál es la velocidad de infusión?',	NULL,	NULL),
(309,	83,	5,	'La velocidad de infusión de HyQvia es incremental y depende del peso del paciente.\n\n*   **Pacientes que pesan menos de 40 kg:** La velocidad inicial es baja y se aumenta gradualmente hasta un máximo de 160 mL/h.\n*   **Pacientes que pesan 40 kg o más:** La velocidad inicial es baja y se aumenta gradualmente hasta un máximo de 300 mL/h.\n\nEs fundamental seguir las instrucciones de administración y aumentar la velocidad de forma gradual para asegurar una correcta tolerancia.\n\nAhora, para continuar con tu capacitación, me gustaría que me explicaras brevemente qué son las reacciones adversas sistémicas y locales en el contexto de HyQvia.',	'/coach-app/mp3/68811f4ff39c5.mp3',	'Las reacciones locales son solamente en el sitio de infusión, y las reacciones sistémicas pueden ser graves.',	NULL,	NULL),
(310,	83,	6,	'¡Buen intento, Rogelio! Estás en el camino correcto, pero vamos a precisar un poco más:\n\n*   **Reacciones locales:** Son las más comunes y se limitan al sitio de infusión. Pueden incluir inflamación, dolor o prurito (picazón) y generalmente son leves.\n*   **Reacciones sistémicas:** Aunque menos frecuentes, pueden incluir síntomas como cefalea, fatiga, náuseas, etc. Ocurren con menor frecuencia que con la IVIg tradicional.\n\n¿Tienes alguna duda sobre esto, Rogelio? Ahora, para continuar, me gustaría que me explicaras qué es la biodisponibilidad en relación con HyQvia.',	'/coach-app/mp3/68811f8d24606.mp3',	'Es la cantidad de inmunoglobulina que se encuentra disponible en el torrente sanguíneo.',	NULL,	NULL),
(311,	83,	7,	'¡Excelente, Rogelio! Esa es una definición muy acertada.\n\nLa biodisponibilidad se refiere al porcentaje de la dosis de inmunoglobulina que alcanza la circulación sistémica. HyQvia mejora la biodisponibilidad en aproximadamente un 20 % en comparación con la SCIg convencional, gracias a la acción de la rHuPH20. Esto significa que una mayor cantidad de inmunoglobulina llega a donde se necesita para combatir las infecciones.\n\n¿Te gustaría que abordáramos algún otro aspecto de HyQvia o del sistema inmunológico, Rogelio?',	'/coach-app/mp3/68811fc530525.mp3',	'Diagnóstico de las IDP.',	NULL,	NULL),
(312,	83,	8,	'Rogelio, el diagnóstico de las Inmunodeficiencias Primarias (IDP) implica una serie de pasos:\n\n1.  **Historia clínica:** Se evalúan los antecedentes del paciente y la presencia de infecciones recurrentes o inusuales.\n2.  **Recuento leucocitario y niveles de IgG:** Se realizan análisis de sangre para medir los niveles de inmunoglobulinas y evaluar las células inmunitarias.\n3.  **Test de vacunación:** Se evalúa la respuesta del paciente a las vacunas para determinar la capacidad de generar anticuerpos.\n4.  **Test genético:** En algunos casos, se realizan pruebas genéticas para identificar mutaciones específicas que causan la IDP.\n\nEl diagnóstico temprano es crucial para iniciar el tratamiento adecuado y mejorar la calidad de vida del paciente.\n\n¿Tienes alguna pregunta sobre este tema, Rogelio?',	'/coach-app/mp3/68811ff3ba309.mp3',	'¿Cómo se hace el test genético?',	NULL,	NULL),
(313,	83,	9,	'Rogelio, el test genético para IDP generalmente implica el análisis de una muestra de sangre del paciente.\n\nEn el laboratorio, se extrae el ADN de las células sanguíneas y se analiza para buscar mutaciones en los genes que se sabe que están relacionados con las IDP. Se pueden utilizar diferentes técnicas, como secuenciación de genes individuales o paneles de genes, dependiendo de la sospecha clínica y la disponibilidad de recursos. Los resultados del test genético pueden confirmar el diagnóstico de IDP y ayudar a identificar el tipo específico de inmunodeficiencia que padece el paciente.\n\n¿Te gustaría saber algo más sobre este tema, Rogelio?',	'/coach-app/mp3/68812031ab1fd.mp3',	'No, gracias.',	NULL,	NULL),
(314,	83,	10,	'¡De nada, Rogelio! Ha sido un placer guiarte en esta sesión de coaching sobre HyQvia. Has demostrado un buen entendimiento de los conceptos clave. Te animo a seguir aprendiendo y profundizando en tus conocimientos sobre este importante tratamiento y el sistema inmunológico.\n\nSi tienes alguna otra pregunta en el futuro, no dudes en consultarme. ¡Mucho éxito!',	'/coach-app/mp3/68812062b8c37.mp3',	'Gracias, Jaime.',	NULL,	NULL),
(315,	83,	11,	'¡A ti, Rogelio! ¡Que tengas un excelente día!',	'/coach-app/mp3/68812083263b7.mp3',	'Jaime, ¿qué son las inmunodeficiencias secundarias?',	NULL,	NULL),
(316,	83,	12,	'¡Excelente pregunta, Rogelio!\n\nLas inmunodeficiencias secundarias (IDS) son aquellas que se adquieren como consecuencia de otras condiciones o tratamientos, a diferencia de las IDP que son genéticas.\n\nLas causas comunes de IDS incluyen:\n\n*   **Neoplasias hematológicas:** Como leucemia linfocítica crónica, linfoma o mieloma múltiple.\n*   **Fármacos inmunosupresores:** Como corticosteroides, quimioterapia o medicamentos utilizados en trasplantes.\n*   **Infección por VIH.**\n\nEn general, las IDS se caracterizan por una disminución en la función del sistema inmunitario, lo que aumenta la susceptibilidad a infecciones.\n\n¿Te gustaría que profundizáramos en algún aspecto específico de las IDS, Rogelio?',	'/coach-app/mp3/6881209579290.mp3',	'Indicaciones de HyQvia.',	NULL,	NULL),
(317,	83,	13,	'¡Muy bien, Rogelio!\n\nHyQvia está indicado para el tratamiento de:\n\n*   **Inmunodeficiencias Primarias (IDP):**\n    *   Agammaglobulinemia congénita o agammaglobulinemia ligada al cromosoma X.\n    *   Inmunodeficiencia común variable (IDCV).\n    *   Inmunodeficiencias combinadas graves (IDCG).\n    *   Deficiencias de subclases de IgG, con infecciones recurrentes.\n*   **Inmunodeficiencias Secundarias (IDS):**\n    *   Hipogammaglobulinemia grave e infecciones recurrentes en pacientes con leucemia linfocítica crónica (LLC) o mieloma múltiple (MM).\n\nEs importante destacar que HyQvia está indicado en adultos y también en pacientes pediátricos (de 0 a 18 años) que cumplen con los criterios mencionados.\n\n¿Tienes alguna otra pregunta sobre las indicaciones de HyQvia, Rogelio?',	'/coach-app/mp3/688120ce4676b.mp3',	'Gracias.',	NULL,	NULL),
(318,	83,	14,	'De nada, Rogelio. Ha sido un placer ayudarte a entender mejor las indicaciones de HyQvia. Si surge alguna otra pregunta, no dudes en consultarme. ¡Sigue aprendiendo!',	'/coach-app/mp3/688121053fcf3.mp3',	'Oye, Jaime.',	NULL,	NULL),
(319,	83,	15,	'¡Hola de nuevo, Rogelio! ¿En qué puedo ayudarte?',	'/coach-app/mp3/6881211be9bb0.mp3',	'Diferencias entre IDP y IDS.',	NULL,	NULL),
(320,	83,	16,	'¡Excelente pregunta, Rogelio! Es fundamental comprender las diferencias entre las Inmunodeficiencias Primarias (IDP) y las Inmunodeficiencias Secundarias (IDS).\n\nAquí te presento las diferencias clave:\n\n*   **Causa:**\n    *   IDP: Causadas por defectos genéticos heredados.\n    *   IDS: Causadas por otras condiciones o tratamientos adquiridos.\n*   **Origen:**\n    *   IDP: Presentes desde el nacimiento o se manifiestan en la infancia.\n    *   IDS: Se desarrollan a lo largo de la vida, como consecuencia de factores externos.\n*   **Ejemplos de causas:**\n    *   IDP: Defectos en genes que afectan a las células B o T.\n    *   IDS: Cáncer, VIH, tratamientos inmunosupresores.\n*   **Tratamiento:**\n    *   IDP: A menudo requieren terapia de reemplazo con inmunoglobulinas (Ig), trasplante de médula ósea o tratamientos específicos para el defecto genético.\n    *   IDS: El tratamiento se enfoca en la condición subyacente que causa la inmunodeficiencia, además de la terapia con Ig si es necesario.\n\n¿Te queda claro, Rogelio? ¿Te gustaría que profundizáramos en algún aspecto específico?',	'/coach-app/mp3/6881214291255.mp3',	NULL,	NULL,	NULL),
(321,	83,	17,	'¡Perfecto! Me alegra que te haya quedado claro. ¿En qué más puedo ayudarte hoy, Rogelio? ¿Tienes alguna otra pregunta sobre HyQvia o sobre algún otro aspecto del sistema inmunológico?',	'/coach-app/mp3/6881219b68bf0.mp3',	NULL,	NULL,	NULL),
(322,	83,	18,	'¡Entendido, Rogelio! Si en algún momento te surge alguna duda, no dudes en consultarme. Estoy aquí para apoyarte en tu aprendizaje. ¡Que tengas un excelente día!',	'/coach-app/mp3/688121b06db1f.mp3',	'Luego, Jaime.',	NULL,	NULL),
(323,	83,	19,	'¡Hasta luego, Rogelio! ¡Un placer haberte acompañado en este proceso! ¡Sigue adelante!',	'/coach-app/mp3/688121c44c20d.mp3',	NULL,	NULL,	NULL),
(324,	83,	20,	'¡Perfecto, Rogelio! Recuerda que estoy aquí para ayudarte en cualquier momento. ¡No dudes en contactarme si tienes alguna pregunta!',	'/coach-app/mp3/688121d258753.mp3',	NULL,	NULL,	NULL),
(325,	84,	1,	'¡Hola Yolanda! Soy Jaime, tu tutor experto en HyQvia. Estoy aquí para guiarte en este proceso de aprendizaje. Para comenzar, me gustaría evaluar tus conocimientos sobre HyQvia.\n\nPrimero, necesito que me expliques brevemente en tus propias palabras los siguientes conceptos clave relacionados con HyQvia:\n\n1) fSCIG (facilitated subcutaneous immunoglobulin)\nModalidad de administración subcutánea que combina inmunoglobulina humana al 10 % con hialuronidasa recombinante para permitir dosis mensuales completas en uno o dos sitios de infusión.\n\n2) rHuPH20 (hialuronidasa humana recombinante)\nEnzima que degrada temporalmente el hialuronano de la matriz subcutánea, aumentando su permeabilidad para absorber volúmenes elevados de inmunoglobulina en una sola infusión mensual.\n\n3) Biodisponibilidad\nPorcentaje de la dosis de inmunoglobulina que alcanza la circulación sistémica; HyQvia mejora la biodisponibilidad ~20 % respecto al SCIg convencional gracias a la acción de rHuPH20.\n\n4) Variabilidad pico-valle\nFluctuación entre las concentraciones máximas y mínimas de IgG sérica; HyQvia ofrece niveles más estables (menor variabilidad) frente a la IVIg, reduciendo picos y valles clínicamente relevantes.\n\n5) Reacciones adversas sistémicas vs. locales\n\nLocales: inflamación, dolor o prurito en el sitio de infusión (predominantes y generalmente leves).\n\nSistémicas: cefalea, fatiga, náuseas; ocurren con menor frecuencia que en la IVIg tradicional.\n\n¿Estás lista para empezar?',	'/coach-app/mp3/6886ca3d91ae4.mp3',	NULL,	NULL,	NULL),
(326,	84,	2,	'¡Perfecto, Yolanda! Comencemos con la primera pregunta.\n\nDe acuerdo a la lista que te di, necesito que me expliques el termino #3, Biodisponibilidad, en tus propias palabras.',	'/coach-app/mp3/6886caa6ca1e1.mp3',	'De la dosis de inmunoglobulina que alcanza la circulación sistémica. Con HyQvia, esta mejora el 20 por ciento en comparación a otras subcutáneas, a otras gamas subcutáneas.',	NULL,	NULL),
(327,	84,	3,	'¡Muy bien, Yolanda! Tu explicación es correcta en esencia. La biodisponibilidad se refiere al porcentaje de la dosis de inmunoglobulina que llega a la circulación sanguínea.\n\nPara ser más precisos, HyQvia mejora la biodisponibilidad en aproximadamente un 20% en comparación con la inmunoglobulina subcutánea convencional, gracias a la acción de la rHuPH20. Esto significa que una mayor cantidad de anticuerpos administrados con HyQvia están disponibles para combatir las infecciones.\n\n¿Tienes alguna duda sobre este concepto?',	'/coach-app/mp3/6886cad09cd3e.mp3',	'Y la hialuronidasa.',	NULL,	NULL),
(328,	84,	4,	'¡Excelente pregunta, Yolanda! La hialuronidasa recombinante (rHuPH20) es una enzima clave en el funcionamiento de HyQvia.\n\nEn tus propias palabras, ¿cómo describirías la función de la rHuPH20?',	'/coach-app/mp3/6886cafa98eda.mp3',	'La RU 20 es la hialuronidasa que va a permitir que el espacio entre la piel y la dermis permita que la gama se absorba rápidamente. De esta manera, vamos a administrar HyQvia una vez al mes en 2 sitios de aplicación.',	NULL,	NULL),
(329,	84,	5,	'¡Muy bien, Yolanda! Tu explicación es muy clara.\n\nLa rHuPH20, o hialuronidasa recombinante, es la enzima que facilita la administración subcutánea de HyQvia. Lo hace degradando temporalmente el ácido hialurónico, que es un componente de la matriz subcutánea. Esto aumenta la permeabilidad de los tejidos, permitiendo que la inmunoglobulina se disperse y se absorba de manera más eficiente. Como mencionaste, esto permite la administración de dosis mensuales completas en uno o dos sitios de infusión.\n\nAhora, para asegurarnos de que dominas los conceptos clave, me gustaría que me explicaras el término \"Variabilidad pico-valle\" en tus propias palabras.',	'/coach-app/mp3/6886cb2b46ace.mp3',	'Variabilidad es la cantidad de medicamento que se va a encontrar en sangre. Esto le va a permitir a HyQvia tener una dosis de inmunoglobulina que alcance la circulación sistémica para poder administrarla una vez al mes y disminuir las inyecciones o los sitios de aplicación, como pasa con otras gamas subcutáneas.',	NULL,	NULL),
(330,	84,	6,	'Yolanda, tu explicación es muy buena y refleja una comprensión sólida del concepto.\n\nLa \"variabilidad pico-valle\" se refiere a las fluctuaciones en los niveles de IgG en la sangre. HyQvia, gracias a su formulación y la acción de la rHuPH20, ayuda a mantener niveles más estables de IgG en comparación con otras terapias. Esto significa que hay menos variaciones entre las concentraciones máximas (pico) y mínimas (valle) de IgG, lo que se traduce en una mejor protección contra las infecciones a lo largo del tiempo.\n\n¿Te queda alguna duda sobre este tema? Si no, podemos pasar a la siguiente pregunta.',	'/coach-app/mp3/6886cb77ed969.mp3',	NULL,	NULL,	NULL),
(331,	84,	7,	'¡Perfecto!\n\nAhora, quiero que me expliques la diferencia entre las reacciones adversas \"sistémicas\" y \"locales\" asociadas con HyQvia. ¿Cuáles son las más comunes y cómo se diferencian?',	'/coach-app/mp3/6886cba9a3a7c.mp3',	'Se pueden clasificar en dos tipos principales. Las reacciones locales son más comunes y suelen ser de leves a transitorias: inflamación en el sitio de la aplicación, dolor, en algunas ocasiones prurito. Las reacciones secundarias sistémicas son, con mayor frecuencia, cefalea, fatiga, náusea y, en algunas ocasiones, vómito.',	NULL,	NULL),
(332,	84,	8,	'¡Excelente, Yolanda! Has descrito muy bien la diferencia entre las reacciones locales y sistémicas.\n\nComo bien has dicho, las reacciones locales son más frecuentes y suelen ser leves, como inflamación, dolor o picazón en el sitio de la inyección. Las reacciones sistémicas, aunque menos comunes, pueden incluir síntomas como dolor de cabeza, fatiga, náuseas y, en algunos casos, vómitos.\n\n¿Te gustaría que profundicemos en algún aspecto de estas reacciones o prefieres que avancemos?',	'/coach-app/mp3/6886cbdcb000f.mp3',	NULL,	NULL,	NULL),
(333,	84,	9,	'¡Continuemos entonces!\n\nAhora, Yolanda, te voy a hacer una pregunta un poco diferente. ¿Qué te parece más ventajoso de HyQvia en comparación con la IVIg (inmunoglobulina intravenosa) y la SCIg (inmunoglobulina subcutánea convencional)?',	'/coach-app/mp3/6886cbff782a4.mp3',	'La principal es que el paciente no va a tener mayor trauma al estar sentado por muchas horas en cuanto a la aplicación de la inmunoglobulina intravenosa. Se corren riesgos de infecciones intrahospitalarias. En cuanto a la inmunoglobulina subcutánea, es muchísimo más fácil de administrar y, en este caso, HyQvia va a permitir que, en vez de que el paciente se administre cada semana la dosis de inmunoglobulina subcutánea, ahora lo pueda hacer con HyQvia exclusivamente una vez al mes, en uno o en dos sitios.',	NULL,	NULL),
(334,	84,	10,	'¡Excelente resumen, Yolanda! Has destacado los puntos clave.\n\nHyQvia ofrece varias ventajas significativas:\n\n*   **Comodidad:** Reduce el tiempo de tratamiento y la necesidad de acudir a un centro de salud, a diferencia de la IVIg.\n*   **Menos frecuentes:** Menos inyecciones y sitios de aplicación en comparación con la SCIg convencional, lo que mejora la adherencia al tratamiento y la calidad de vida del paciente.\n\n¿Hay algo más que te gustaría saber sobre HyQvia o sobre cómo se compara con otras opciones de tratamiento?',	'/coach-app/mp3/6886cc456f6a4.mp3',	'Un poco más, sobre todo de las de la gama intravenosa, conozco muy poco.',	NULL,	NULL),
(335,	84,	11,	'¡Claro, Yolanda! Es normal tener menos conocimiento sobre la IVIg si te enfocas principalmente en HyQvia.\n\nLa IVIg se administra directamente en una vena, lo que significa que la inmunoglobulina entra en la circulación sanguínea de manera rápida. Esto puede ser beneficioso en situaciones donde se necesita un efecto inmediato, pero también conlleva algunos inconvenientes.\n\n¿Qué te gustaría saber específicamente sobre la IVIg? Por ejemplo, podríamos hablar de sus indicaciones, la forma en que se administra, los posibles efectos secundarios, etc.',	'/coach-app/mp3/6886cc73c8ea8.mp3',	NULL,	NULL,	NULL),
(336,	84,	12,	'¡Entendido! Como hemos revisado los conceptos clave y las ventajas de HyQvia, ¿tienes alguna otra pregunta sobre el producto, su administración o su uso en el tratamiento de las inmunodeficiencias? Si no, podemos pasar a otro tema.',	'/coach-app/mp3/6886cc9b86068.mp3',	'Secundarias, por favor.',	NULL,	NULL),
(337,	84,	13,	'¡Perfecto, Yolanda! Hablemos de las Inmunodeficiencias Secundarias (IDS).\n\nLas IDS son aquellas que se desarrollan como consecuencia de otras enfermedades o tratamientos, a diferencia de las IDP que son de origen genético. Las causas más comunes de IDS incluyen:\n\n*   **Neoplasias hematológicas:** Como la leucemia linfocítica crónica, el linfoma y el mieloma múltiple.\n*   **Fármacos inmunosupresores:** Como los corticosteroides, bortezomib, etc.\n*   **Quimioterapia:** Utilizada en el tratamiento del cáncer.\n*   **VIH:** El virus de la inmunodeficiencia humana.\n\nEn cuanto al manejo de las IDS, ¿qué te gustaría saber específicamente? Podemos hablar de cómo se diagnostican, cómo se tratan, o cómo se utiliza HyQvia en su manejo.',	'/coach-app/mp3/6886ccb2c3d8c.mp3',	NULL,	NULL,	NULL),
(338,	84,	14,	'¡Excelente pregunta, Yolanda!\n\nEn el contexto de las IDS, la terapia de reemplazo con inmunoglobulinas (IgRT) con HyQvia se considera si el paciente presenta:\n\n*   Infecciones recurrentes o graves.\n*   Una respuesta inadecuada a las vacunas.\n*   Niveles bajos de IgG en sangre.\n\nLa dosis de HyQvia en IDS suele ser individualizada, generalmente entre 0,2 y 0,4 g/kg cada 3 o 4 semanas, pero esto puede variar según la gravedad de la inmunodeficiencia y la respuesta del paciente.\n\n¿Tienes alguna pregunta sobre este tema?',	'/coach-app/mp3/6886cce734836.mp3',	'Las inmunodeficiencias secundarias.',	NULL,	NULL),
(339,	84,	15,	'¡Comprendo, Yolanda! Profundicemos un poco más en el tema de las Inmunodeficiencias Secundarias (IDS).\n\nEn las IDS, es crucial identificar y tratar la causa subyacente de la inmunodeficiencia, si es posible. Además de la terapia con inmunoglobulinas, el manejo de las IDS puede incluir:\n\n*   **Tratamiento de la enfermedad subyacente:** Por ejemplo, quimioterapia para el cáncer o tratamiento antirretroviral para el VIH.\n*   **Medidas de soporte:** Como el uso de antibióticos para tratar o prevenir infecciones, y el apoyo nutricional.\n*   **Monitoreo:** Es fundamental vigilar de cerca al paciente para detectar y tratar oportunamente las infecciones y evaluar la respuesta al tratamiento.\n\n¿Te gustaría saber más sobre algún aspecto específico del manejo de las IDS, como la elección de la dosis de HyQvia, el seguimiento de los pacientes o las consideraciones especiales para ciertos grupos de pacientes?',	'/coach-app/mp3/6886cd1515fc6.mp3',	NULL,	NULL,	NULL),
(340,	84,	16,	'¡Perfecto!\n\nAhora, para asegurarnos de que estás comprendiendo bien, te propongo un pequeño ejercicio. Imagina que tienes un paciente con mieloma múltiple que está experimentando infecciones recurrentes. El médico, después de evaluar al paciente, decide iniciar terapia con HyQvia.\n\n¿Qué consideraciones clave tendrías en cuenta al educar a este paciente sobre el tratamiento con HyQvia?',	'/coach-app/mp3/6886cd4e5f979.mp3',	NULL,	NULL,	NULL),
(341,	85,	1,	'Interacción 1:\n\nHola Rogelio Lázaro, mi nombre es Jaime y seré tu tutor experto en HyQvia.  Antes de empezar, me gustaría que me explicaras en tus propias palabras los términos fSCIG y rHuPH20.  Esto nos ayudará a asegurar una base sólida para nuestra sesión de coaching.',	'/coach-app/mp3/6892e3afe6d73.mp3',	'REMOTE_CONTENT_ERROR: The remote server hosting the media returned a client error: 404 Not Found. - https://rolplayadmin.com/coach-app/videos/RecordRTC-202576-ec2e3ql8z0k.wav',	NULL,	NULL),
(342,	85,	2,	'Interacción 2:\n\nHe escogido al azar un término para que me lo expliques.  Por favor, explica \"Biodisponibilidad\" en tus propias palabras,  como si estuvieras explicándoselo a un paciente.',	'/coach-app/mp3/6892e3d843452.mp3',	'REMOTE_CONTENT_ERROR: The remote server hosting the media returned a client error: 404 Not Found. - https://rolplayadmin.com/coach-app/videos/RecordRTC-202576-4wnjt27dsw7.wav',	NULL,	NULL),
(343,	85,	3,	'Interacción 3:\n\nBien Rogelio, la biodisponibilidad se refiere a la cantidad de medicamento que llega al torrente sanguíneo y está disponible para actuar en el cuerpo. En el caso de HyQvia,  una mayor biodisponibilidad significa que una mayor proporción de la inmunoglobulina administrada alcanza la circulación sanguínea para combatir las infecciones, en comparación con otros métodos de administración. ¿Tienes alguna duda sobre este concepto?',	'/coach-app/mp3/6892e3f61c46f.mp3',	'REMOTE_CONTENT_ERROR: The remote server hosting the media returned a client error: 404 Not Found. - https://rolplayadmin.com/coach-app/videos/RecordRTC-202576-3i5qhhv3stf.wav',	NULL,	NULL),
(344,	85,	4,	'Interacción 4:\n\nNo hay problema Rogelio.  Ahora, explícame en tus propias palabras qué significa \"Variabilidad pico-valle\" en el contexto de la terapia de reemplazo de inmunoglobulinas.',	'/coach-app/mp3/6892e41e873fa.mp3',	'REMOTE_CONTENT_ERROR: The remote server hosting the media returned a client error: 404 Not Found. - https://rolplayadmin.com/coach-app/videos/RecordRTC-202576-6gghuyjr5yg.wav',	NULL,	NULL),
(345,	85,	5,	'Interacción 5:\n\nRogelio, la variabilidad pico-valle se refiere a las fluctuaciones en los niveles de inmunoglobulina en sangre a lo largo del tiempo.  Un pico alto representa una concentración máxima y un valle bajo representa la concentración mínima.  Una menor variabilidad significa que los niveles se mantienen más estables, evitando tanto niveles demasiado bajos como demasiado altos, lo cual es beneficioso para la eficacia y la seguridad del tratamiento. ¿Te queda claro?',	'/coach-app/mp3/6892e4364cf80.mp3',	'REMOTE_CONTENT_ERROR: The remote server hosting the media returned a client error: 404 Not Found. - https://rolplayadmin.com/coach-app/videos/RecordRTC-202576-92h9rk4hsg.wav',	NULL,	NULL),
(346,	85,	6,	'Interacción 6:\n\nPerfecto Rogelio.  Tu comprensión del concepto es correcta.  Recuerda que cualquier duda que tengas sobre HyQvia o el sistema inmunológico en relación con el producto, no dudes en preguntarme.  Estoy aquí para ayudarte.',	'/coach-app/mp3/6892e46521795.mp3',	'REMOTE_CONTENT_ERROR: The remote server hosting the media returned a client error: 404 Not Found. - https://rolplayadmin.com/coach-app/videos/RecordRTC-202576-lgae2za7tpg.wav',	NULL,	NULL),
(347,	85,	7,	'Interacción 7:\n\nClaro que sí, Rogelio.  Dime qué te gustaría saber.',	'/coach-app/mp3/6892e482780b0.mp3',	'REMOTE_CONTENT_ERROR: The remote server hosting the media returned a client error: 404 Not Found. - https://rolplayadmin.com/coach-app/videos/RecordRTC-202576-ivl7c8drsm.wav',	NULL,	NULL),
(348,	85,	8,	'Interacción 8:\n\nCon gusto, Rogelio.  ¿Sobre qué aspecto de HyQvia o su relación con el sistema inmunológico te gustaría profundizar?',	'/coach-app/mp3/6892e497d2c5f.mp3',	'REMOTE_CONTENT_ERROR: The remote server hosting the media returned a client error: 404 Not Found. - https://rolplayadmin.com/coach-app/videos/RecordRTC-202576-5mml3206sag.wav',	NULL,	NULL),
(349,	85,	9,	'Interacción 9:\n\nLas reacciones adversas locales son las más comunes con HyQvia y generalmente son leves, como inflamación, dolor o picazón en el sitio de inyección.  Las reacciones sistémicas, como cefalea o fatiga, son menos frecuentes que con la administración intravenosa de inmunoglobulinas.  ¿Hay algo más específico que te gustaría saber sobre las reacciones adversas?',	'/coach-app/mp3/6892e4ab59d3e.mp3',	'REMOTE_CONTENT_ERROR: The remote server hosting the media returned a client error: 404 Not Found. - https://rolplayadmin.com/coach-app/videos/RecordRTC-202576-ai55jwudqmq.wav',	NULL,	NULL),
(350,	85,	10,	'Interacción 10:\n\nLa posología de HyQvia se ajusta a las necesidades individuales del paciente y a si tiene una IDP o una IDS.  Para pacientes con IDP sin tratamiento previo, la dosis suele ser de 0.4 a 0.8 g/kg al mes.  Para pacientes que cambian de IVIg, se mantiene la misma dosis y frecuencia. En el caso de IDS, la dosis es típicamente de 0.2 a 0.4 g/kg cada 3-4 semanas.  ¿Necesitas más detalles sobre algún caso específico?',	'/coach-app/mp3/6892e4cd83bae.mp3',	'REMOTE_CONTENT_ERROR: The remote server hosting the media returned a client error: 404 Not Found. - https://rolplayadmin.com/coach-app/videos/RecordRTC-202576-evj59htb8x.wav',	NULL,	NULL),
(351,	85,	11,	'Interacción 11:\n\nHyQvia contiene inmunoglobulina humana normal al 10% y rHuPH20. La inmunoglobulina se une a los patógenos, activando el complemento y facilitando la opsonización para eliminarlos.  La rHuPH20, o hialuronidasa recombinante humana, aumenta la permeabilidad del tejido subcutáneo, permitiendo la administración de mayores volúmenes de inmunoglobulina en una sola inyección. ¿Te gustaría más información sobre alguno de estos componentes?',	'/coach-app/mp3/6892e4fc0e06b.mp3',	'REMOTE_CONTENT_ERROR: The remote server hosting the media returned a client error: 404 Not Found. - https://rolplayadmin.com/coach-app/videos/RecordRTC-202576-1mbpvnpxxho.wav',	NULL,	NULL),
(352,	86,	1,	'Interacción 1:\n\nHola Rogelio Lazaro, soy Jaime, tu tutor experto en HyQvia.  Antes de empezar a profundizar en el producto, quiero asegurarme de que tienes una base sólida.  Te haré dos preguntas sobre términos clave relacionados con HyQvia: fSCIG y rHuPH20.  ¿Estás listo?',	'/coach-app/mp3/689396fa3175b.mp3',	'REMOTE_CONTENT_ERROR: The remote server hosting the media returned a client error: 404 Not Found. - https://rolplayadmin.com/coach-app/videos/RecordRTC-202576-10dlnqibl2g.wav',	NULL,	NULL),
(353,	86,	2,	'Interacción 2:\n\nRogelio Lazaro,  explica en tus propias palabras el significado de  \"Biodisponibilidad\" en el contexto de HyQvia.',	'/coach-app/mp3/68939789bc61a.mp3',	'REMOTE_CONTENT_ERROR: The remote server hosting the media returned a client error: 404 Not Found. - https://rolplayadmin.com/coach-app/videos/RecordRTC-202576-eixch2wnjk.wav',	NULL,	NULL),
(354,	86,	3,	'Interacción 3:\n\nLa biodisponibilidad se refiere a la proporción de la dosis de inmunoglobulina que llega al torrente sanguíneo.  En el caso de HyQvia, la adición de rHuPH20 mejora la biodisponibilidad aproximadamente un 20% en comparación con la inmunoglobulina subcutánea convencional (SCIg).  ¿Alguna duda sobre este concepto, Rogelio Lazaro?',	'/coach-app/mp3/6893979fdea96.mp3',	'REMOTE_CONTENT_ERROR: The remote server hosting the media returned a client error: 404 Not Found. - https://rolplayadmin.com/coach-app/videos/RecordRTC-202576-djfy7agj4xi.wav',	NULL,	NULL),
(355,	87,	1,	'Interacción 1:\n\nHola Rogelio Lázaro, soy Jaime, tu tutor experto en HyQvia.  Antes de comenzar, necesito que me expliques en tus propias palabras dos conceptos clave: 1) fSCIG (inmunoglobulina subcutánea facilitada) y 2) rHuPH20 (hialuronidasa humana recombinante).  Esto nos ayudará a asegurar que estamos en la misma página.',	'/coach-app/mp3/68951cb64baae.mp3',	'REMOTE_CONTENT_ERROR: The remote server hosting the media returned a client error: 404 Not Found. - https://rolplayadmin.com/coach-app/videos/RecordRTC-202577-6gc8jdh9qpy.wav',	NULL,	NULL),
(356,	87,	2,	'Interacción 2:\n\n(Jaime escoge aleatoriamente el número 3.  Por lo tanto, la pregunta será sobre Biodisponibilidad).\n\nRogelio Lázaro, ¿puedes explicarme qué significa \"biodisponibilidad\" en el contexto de HyQvia?',	'/coach-app/mp3/68951cdbd8514.mp3',	'REMOTE_CONTENT_ERROR: The remote server hosting the media returned a client error: 404 Not Found. - https://rolplayadmin.com/coach-app/videos/RecordRTC-202577-iis8h2ku05e.wav',	NULL,	NULL),
(357,	87,	3,	'Interacción 3:\n\nRogelio Lázaro, tu respuesta está en el buen camino, pero podemos ser más precisos.  La biodisponibilidad se refiere al porcentaje de la dosis de inmunoglobulina que llega al torrente sanguíneo.  HyQvia mejora la biodisponibilidad aproximadamente un 20% en comparación con la inmunoglobulina subcutánea convencional (SCIg), gracias a la acción de la rHuPH20. ¿Tienes alguna duda sobre este concepto?',	'/coach-app/mp3/68951cfcb6993.mp3',	'REMOTE_CONTENT_ERROR: The remote server hosting the media returned a client error: 404 Not Found. - https://rolplayadmin.com/coach-app/videos/RecordRTC-202577-fm1w61keay.wav',	NULL,	NULL),
(358,	87,	4,	'Interacción 4:\n\nNo hay problema, Rogelio Lázaro.  La rHuPH20 es esencial para la eficacia de HyQvia.  Ahora,  explica \"variabilidad pico-valle\" en tus propias palabras, por favor.',	'/coach-app/mp3/68951d2607614.mp3',	'REMOTE_CONTENT_ERROR: The remote server hosting the media returned a client error: 404 Not Found. - https://rolplayadmin.com/coach-app/videos/RecordRTC-202577-aprfy4dmivc.wav',	NULL,	NULL),
(359,	87,	5,	'Interacción 5:\n\nRogelio Lázaro,  tu explicación de la variabilidad pico-valle es correcta en su esencia, pero podemos mejorarla. Se refiere a la fluctuación entre los niveles máximos y mínimos de IgG en la sangre. HyQvia, al proporcionar niveles más constantes, reduce estas fluctuaciones en comparación con la IVIg.  Esto significa menos picos y valles de concentración de IgG, lo cual es beneficioso para el paciente. ¿Entiendes mejor ahora?',	'/coach-app/mp3/68951d3f15726.mp3',	'REMOTE_CONTENT_ERROR: The remote server hosting the media returned a client error: 404 Not Found. - https://rolplayadmin.com/coach-app/videos/RecordRTC-202577-io840y88n5f.wav',	NULL,	NULL),
(360,	87,	6,	'Interacción 6:\n\nPerfecto, Rogelio Lázaro.  Recuerda que la clave es la comprensión precisa de estos conceptos. Ahora, pregúntame cualquier cosa que te interese sobre HyQvia o el sistema inmunológico en general. Estoy aquí para ayudarte.',	'/coach-app/mp3/68951d667a234.mp3',	'REMOTE_CONTENT_ERROR: The remote server hosting the media returned a client error: 404 Not Found. - https://rolplayadmin.com/coach-app/videos/RecordRTC-202577-43ozrgphvie.wav',	NULL,	NULL),
(361,	87,	7,	'Interacción 7:\n\nRogelio Lázaro,  las reacciones adversas locales son más frecuentes con HyQvia que las sistémicas, pero generalmente son leves.  Se manifiestan como inflamación, dolor o picazón en el sitio de la inyección.  Las reacciones sistémicas, como cefalea, fatiga o náuseas, son menos comunes que con la IVIg.  ¿Te gustaría profundizar en algún aspecto específico de las reacciones adversas?',	'/coach-app/mp3/68951d8a19ad4.mp3',	'REMOTE_CONTENT_ERROR: The remote server hosting the media returned a client error: 404 Not Found. - https://rolplayadmin.com/coach-app/videos/RecordRTC-202577-lhtq3344e.wav',	NULL,	NULL),
(362,	87,	8,	'Interacción 8:\n\nRogelio Lázaro,  la posología de HyQvia depende del paciente y su historial.  Para pacientes con IDP sin tratamiento previo, se recomienda una dosis inicial de 0.4 a 0.8 g/kg al mes.  Para pacientes que cambian de IVIg, se mantiene la misma dosis y frecuencia.  Si el cambio es desde SCIg convencional, se mantiene la misma dosis pero con intervalos de 3-4 semanas.  En pacientes con IDS, la dosis es de 0.2 a 0.4 g/kg cada 3-4 semanas.  ¿Hay algo en particular sobre la dosificación que te gustaría aclarar?',	'/coach-app/mp3/68951db5f33c5.mp3',	'REMOTE_CONTENT_ERROR: The remote server hosting the media returned a client error: 404 Not Found. - https://rolplayadmin.com/coach-app/videos/RecordRTC-202577-h43orecu7xq.wav',	NULL,	NULL),
(363,	87,	9,	'Interacción 9:\n\nRogelio Lázaro,  HyQvia se administra por vía subcutánea, usualmente en el abdomen o los muslos.  La velocidad de infusión debe incrementarse gradualmente, hasta un máximo de 160 ml/h para pacientes que pesan menos de 40 kg y 300 ml/h para pacientes de 40 kg o más. Recuerda que HyQvia se presenta en dos viales que NO deben mezclarse. ¿Alguna otra duda sobre la administración?',	'/coach-app/mp3/68951de37b5ac.mp3',	'REMOTE_CONTENT_ERROR: The remote server hosting the media returned a client error: 404 Not Found. - https://rolplayadmin.com/coach-app/videos/RecordRTC-202577-3lfxhx3y5ba.wav',	NULL,	NULL),
(364,	87,	10,	'Interacción 10:\n\nRogelio Lázaro,  la  fSCIg (inmunoglobulina subcutánea facilitada)  de HyQvia  combina la inmunoglobulina humana con la rHuPH20. Esta enzima aumenta la permeabilidad del tejido subcutáneo, permitiendo la administración de dosis mensuales completas en uno o dos sitios de inyección.  Esto contrasta con la SCIg convencional, que requiere múltiples sitios de inyección y administración más frecuente. ¿Te queda claro?',	'/coach-app/mp3/68951f5453656.mp3',	'REMOTE_CONTENT_ERROR: The remote server hosting the media returned a client error: 404 Not Found. - https://rolplayadmin.com/coach-app/videos/RecordRTC-202577-d5dfi7ro30j.wav',	NULL,	NULL),
(365,	87,	11,	'Interacción 11:\n\nRogelio Lázaro,  respecto a la seguridad viral, HyQvia se somete a un riguroso proceso de inactivación viral.  Este incluye tratamiento con solventes/detergentes para inactivar virus con envoltura, nanofiltración para eliminar virus lipídicos, e inactivación por calor y pH para eliminar virus como VIH, VHB, VHC y VEMC.  ¿Deseas más detalles sobre algún paso específico del proceso?',	'/coach-app/mp3/68951f7c5a119.mp3',	'REMOTE_CONTENT_ERROR: The remote server hosting the media returned a client error: 404 Not Found. - https://rolplayadmin.com/coach-app/videos/RecordRTC-202577-1j4vb8vepso.wav',	NULL,	NULL),
(366,	88,	1,	'Interacción 1:\n\nHola Rogelio Lázaro, soy Jaime, tu tutor experto en HyQvia.  Antes de comenzar, necesito que me expliques en tus propias palabras dos conceptos clave: 1) fSCIG (inmunoglobulina subcutánea facilitada) y 2) rHuPH20 (hialuronidasa humana recombinante).  Esto nos ayudará a asegurar que estamos en la misma página.',	'/coach-app/mp3/68951cb64baae.mp3',	'REMOTE_CONTENT_ERROR: The remote server hosting the media returned a client error: 404 Not Found. - https://rolplayadmin.com/coach-app/videos/RecordRTC-202577-6gc8jdh9qpy.wav',	NULL,	NULL),
(367,	88,	2,	'Interacción 2:\n\n(Jaime escoge aleatoriamente el número 3.  Por lo tanto, la pregunta será sobre Biodisponibilidad).\n\nRogelio Lázaro, ¿puedes explicarme qué significa \"biodisponibilidad\" en el contexto de HyQvia?',	'/coach-app/mp3/68951cdbd8514.mp3',	'REMOTE_CONTENT_ERROR: The remote server hosting the media returned a client error: 404 Not Found. - https://rolplayadmin.com/coach-app/videos/RecordRTC-202577-iis8h2ku05e.wav',	NULL,	NULL),
(368,	88,	3,	'Interacción 3:\n\nRogelio Lázaro, tu respuesta está en el buen camino, pero podemos ser más precisos.  La biodisponibilidad se refiere al porcentaje de la dosis de inmunoglobulina que llega al torrente sanguíneo.  HyQvia mejora la biodisponibilidad aproximadamente un 20% en comparación con la inmunoglobulina subcutánea convencional (SCIg), gracias a la acción de la rHuPH20. ¿Tienes alguna duda sobre este concepto?',	'/coach-app/mp3/68951cfcb6993.mp3',	'REMOTE_CONTENT_ERROR: The remote server hosting the media returned a client error: 404 Not Found. - https://rolplayadmin.com/coach-app/videos/RecordRTC-202577-fm1w61keay.wav',	NULL,	NULL),
