INSERT INTO `usecase_help_text` (`id`, `usecase_id`, `name_and_template`, `content`, `sys_instruction`, `avatar_config`, `intro_info`, `pronun_help`) VALUES
(7,	7,	'Give a name that is relevant and easy for your users to understand.\r\n\r\nThe usecase templates in the dropdown are the modules that power the whole user interaction. We have put in all the rules and logic that will control the interaction between the avatar and the user. All you have to do is select the correct template based on your needs.',	'This is the place where you put the content that you want the user to interact with. The avatar will take this content and ask questions based on this.',	'This part is optional. The base template already has setup the instructions which control the interaction between the avatar and the user. You can add your own instructions if you like. These instructions will be added to the default instructions.',	'There are some default configuration option which have been set for the avatar. You are free to change them if you like.',	'This is important because this content explains to the first-time user what the usecase is about and what is expected of him. If you have a video hosted somewhere that is relevant to this usecase, the url of that video link cane be put here. \r\n\r\nPlease note that Youtube urls are not valid here.',	'Fix the pronunciation of certain words\r\n\r\nCertain words like technical terms, brand names or proper nouns may not be pronounced correctly in synthesized speech. This module allows you to set the correct pronunciation by changing the spelling of the word. You enter the actual word and then the replacement word for it.\r\nEg.mission:mishun\r\n\r\nNote that the language in use will affect the pronunciation.'),
(9,	10,	'Give a name that is relevant and easy for your users to understand.\r\n\r\nThe usecase templates in the dropdown are the modules that power the whole user interaction. We have put in all the rules and logic that will control the interaction between the avatar and the user. All you have to do is select the correct template based on your needs.',	'This is the place where you put the content that you want the user to interact with. The avatar will take this content and ask questions based on this.',	'This part is optional. The base template already has setup the instructions which control the interaction between the avatar and the user. You can add your own instructions if you like. These instructions will be added to the default instructions.',	'There are some default configuration option which have been set for the avatar. You are free to change them if you like.',	'This is important because this content explains to the first-time user what the usecase is about and what is expected of him. If you have a video hosted somewhere that is relevant to this usecase, the url of that video link cane be put here. \r\n\r\nPlease note that Youtube urls are not valid here.',	'Fix the pronunciation of certain words\r\n\r\nCertain words like technical terms, brand names or proper nouns may not be pronounced correctly in synthesized speech. This module allows you to set the correct pronunciation by changing the spelling of the word. You enter the actual word and then the replacement word for it.\r\nEg.mission:mishun\r\n\r\nNote that the language in use will affect the pronunciation.');
